/**
 * WeatherSystem — Season and weather tracking for Spellroads.
 * Seasons advance every 90 in-game days. Weather changes with RNG on each advance call.
 *
 * Effects applied externally by consumers:
 *   rain / snow      : -10% movement speed
 *   storm / blizzard : -25% movement speed, -1 visibility (fog of war range)
 *   hot              : +1 ration consumed per rest
 *   foggy            : enemies +15% initiative bonus
 *
 * CombatSystem integration (applied at combat start):
 *   blizzard : all movement actions cost +1 AP
 *   storm    : ranged attacks have +20% miss chance
 *
 * @module WeatherSystem
 */

import DebugLog from '../debug/DebugLog.js';
import EventBus from '../core/EventBus.js';

// ─── Data tables ─────────────────────────────────────────────────────────────

const SEASONS = ['spring', 'summer', 'autumn', 'winter'];

const WEATHER_BY_SEASON = {
  spring: ['clear', 'cloudy', 'rainy', 'windy'],
  summer: ['clear', 'clear', 'hot', 'stormy'],
  autumn: ['clear', 'cloudy', 'rainy', 'foggy'],
  winter: ['clear', 'snow', 'blizzard', 'frozen'],
};

/** How many in-game days constitute one season. */
const DAYS_PER_SEASON = 90;

/**
 * Movement-speed multiplier applied by each weather type.
 * 1.0 = no effect; lower values slow the party.
 */
const MOVE_SPEED_MODIFIER = {
  clear:    1.0,
  cloudy:   1.0,
  rainy:    0.90,
  windy:    0.90,
  hot:      1.0,
  stormy:   0.75,
  foggy:    1.0,
  snow:     0.90,
  blizzard: 0.75,
  frozen:   0.90,
};

/**
 * Visibility range modifier (tiles removed from fog-of-war range).
 * Negative values reduce visibility.
 */
const VISIBILITY_MODIFIER = {
  clear:    0,
  cloudy:   0,
  rainy:    0,
  windy:    0,
  hot:      0,
  stormy:  -1,
  foggy:    0,
  snow:     0,
  blizzard:-1,
  frozen:   0,
};

// ─── WeatherSystem ────────────────────────────────────────────────────────────

const WeatherSystem = {
  /** @type {string} Current season name */
  _season: 'spring',

  /** @type {string} Current weather type */
  _weather: 'clear',

  /** @type {number} Intensity 0–1 (used for visual effects, 0=mild, 1=severe) */
  _intensity: 0.5,

  /** @type {boolean} Whether the system has been initialised */
  _initialized: false,

  // ── Public API ──────────────────────────────────────────────────────────────

  /**
   * Initialise WeatherSystem from the current world day.
   * Safe to call multiple times — re-derives state from the day counter.
   *
   * @param {number} [worldDay=1] — Current in-game day (from TimeSystem / WorldState)
   */
  init(worldDay = 1) {
    const seasonIndex = Math.floor((worldDay - 1) / DAYS_PER_SEASON) % SEASONS.length;
    this._season  = SEASONS[seasonIndex];

    // Pick a deterministic starting weather based on the day
    const pool    = WEATHER_BY_SEASON[this._season];
    const wi      = worldDay % pool.length;
    this._weather   = pool[wi];
    this._intensity = 0.5;
    this._initialized = true;

    DebugLog.info(
      `[weather] WeatherSystem initialized; day=${worldDay} season=${this._season} weather=${this._weather}`
    );
  },

  /**
   * Return the current weather state snapshot.
   * @returns {{ season: string, weather: string, intensity: number }}
   */
  getCurrentWeather() {
    return {
      season:    this._season,
      weather:   this._weather,
      intensity: this._intensity,
    };
  },

  /**
   * Advance time by a number of in-game days.
   * May change season and/or weather, emitting events on transitions.
   *
   * @param {number} days — Number of in-game days elapsed
   * @param {number} [currentWorldDay] — Current absolute world day (used for season calc).
   *   If omitted, season changes are tracked incrementally.
   */
  advance(days, currentWorldDay) {
    if (!this._initialized) this.init(currentWorldDay ?? 1);

    const prevSeason  = this._season;
    const prevWeather = this._weather;

    // Recalculate season if we know the absolute day
    if (currentWorldDay !== undefined) {
      const seasonIndex = Math.floor((currentWorldDay - 1) / DAYS_PER_SEASON) % SEASONS.length;
      this._season = SEASONS[seasonIndex];
    }

    // RNG-based weather change — roll on each advance
    const pool = WEATHER_BY_SEASON[this._season];
    // ~60% chance weather changes on each advance call
    if (Math.random() < 0.6) {
      this._weather   = pool[Math.floor(Math.random() * pool.length)];
      this._intensity = Math.random(); // 0–1
    }

    // Emit season:changed if the season turned over
    if (this._season !== prevSeason) {
      DebugLog.info(`[weather] Season changed: ${prevSeason} → ${this._season}`);
      EventBus.emit('season:changed', { season: this._season, prevSeason });
      // When a season changes always pick a fresh weather
      this._weather   = pool[Math.floor(Math.random() * pool.length)];
      this._intensity = Math.random();
    }

    // Emit weather:changed if the weather type changed
    if (this._weather !== prevWeather) {
      DebugLog.event(
        `[weather] Weather changed: ${prevWeather} → ${this._weather}; ` +
        `season=${this._season} intensity=${this._intensity.toFixed(2)}`
      );
      EventBus.emit('weather:changed', this.getCurrentWeather());
    }
  },

  /**
   * Directly set the weather type (for debug commands and save/load).
   * Emits 'weather:changed' unconditionally.
   *
   * @param {string} type — One of the valid weather keys
   * @param {number} [intensity=0.5]
   * @returns {string} Confirmation message
   */
  setWeather(type, intensity = 0.5) {
    const allTypes = [...new Set(Object.values(WEATHER_BY_SEASON).flat())];
    if (!allTypes.includes(type)) {
      const msg = `Unknown weather type "${type}". Valid: ${allTypes.join(', ')}`;
      DebugLog.warn(`[weather] ${msg}`);
      return msg;
    }

    this._weather   = type;
    this._intensity = Math.max(0, Math.min(1, intensity));

    DebugLog.info(`[weather] setWeather → ${type} (intensity=${this._intensity.toFixed(2)})`);
    EventBus.emit('weather:changed', this.getCurrentWeather());

    return `Weather set to ${type}`;
  },

  /**
   * Directly set the season (for debug / testing).
   * Picks a new random weather from the season pool and emits both events.
   *
   * @param {string} season — 'spring' | 'summer' | 'autumn' | 'winter'
   * @returns {string} Confirmation message
   */
  setSeason(season) {
    if (!SEASONS.includes(season)) {
      const msg = `Unknown season "${season}". Valid: ${SEASONS.join(', ')}`;
      DebugLog.warn(`[weather] ${msg}`);
      return msg;
    }
    const prevSeason = this._season;
    this._season = season;

    const pool = WEATHER_BY_SEASON[season];
    this._weather   = pool[Math.floor(Math.random() * pool.length)];
    this._intensity = Math.random();

    DebugLog.info(`[weather] setSeason → ${season}`);
    if (season !== prevSeason) {
      EventBus.emit('season:changed', { season, prevSeason });
    }
    EventBus.emit('weather:changed', this.getCurrentWeather());

    return `Season set to ${season}`;
  },

  /**
   * Get movement speed multiplier for the current weather.
   * @returns {number} Multiplier ≤ 1.0
   */
  getMoveSpeedModifier() {
    return MOVE_SPEED_MODIFIER[this._weather] ?? 1.0;
  },

  /**
   * Get visibility range delta (in tiles) for the current weather.
   * Negative values reduce visible range.
   * @returns {number}
   */
  getVisibilityModifier() {
    return VISIBILITY_MODIFIER[this._weather] ?? 0;
  },

  /**
   * Whether hot weather is active (camp rests consume +1 ration).
   * @returns {boolean}
   */
  isHot() {
    return this._weather === 'hot';
  },

  /**
   * Whether foggy weather is active (enemies get +15% initiative).
   * @returns {boolean}
   */
  isFoggy() {
    return this._weather === 'foggy';
  },

  /**
   * Whether blizzard is active (move actions cost +1 AP in combat).
   * @returns {boolean}
   */
  isBlizzard() {
    return this._weather === 'blizzard';
  },

  /**
   * Whether storm is active (ranged attacks have +20% miss chance in combat).
   * @returns {boolean}
   */
  isStorm() {
    return this._weather === 'stormy';
  },

  /**
   * Human-readable label for the current conditions (season + weather).
   * @returns {string}
   */
  getLabel() {
    const cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);
    return `${cap(this._season)} — ${cap(this._weather)}`;
  },
};

// ─── Debug exposure ───────────────────────────────────────────────────────────

if (typeof window !== 'undefined') {
  window.__debug = window.__debug ?? {};

  /**
   * Set the current weather type.
   * @param {string} type — e.g. 'snow', 'storm', 'clear'
   */
  window.__debug.setweather = (type) => {
    const msg = WeatherSystem.setWeather(type);
    console.info(`[debug] setweather → ${msg}`);
    return msg;
  };

  /**
   * Set the current season.
   * @param {string} season — 'spring' | 'summer' | 'autumn' | 'winter'
   */
  window.__debug.setSeason = (season) => {
    const msg = WeatherSystem.setSeason(season);
    console.info(`[debug] setSeason → ${msg}`);
    return msg;
  };

  /**
   * Get the current weather state.
   * @returns {{ season: string, weather: string, intensity: number }}
   */
  window.__debug.getWeather = () => WeatherSystem.getCurrentWeather();

  // Expose system reference for integration access
  window.__weatherSystem = WeatherSystem;
}

export default WeatherSystem;
