/**
 * CombatSystem — Turn-based combat engine for Spellroads.
 * Manages combat state, turn order, attack resolution, skill execution, AI turns.
 *
 * @module CombatSystem
 */

import DebugLog from '../debug/DebugLog.js';
import CharacterSystem from './CharacterSystem.js';
import SkillSystem from './SkillSystem.js';
import SkillExecutor from './SkillExecutor.js';
import EnemySystem from './EnemySystem.js';
import LootSystem from './LootSystem.js';
import STATUS_EFFECTS from '../data/status_effects.json';
import { createRNG, rollD20, rollRange, pickRandom } from '../utils/RNG.js';
import WeatherSystem from './WeatherSystem.js';

// ─── Constants ────────────────────────────────────────────────────────────────

const GRID_COLS = 8;
const GRID_ROWS = 4;
const PARTY_COLS = [0, 1, 2, 3];
const ENEMY_COLS = [4, 5, 6, 7];

// ─── Helpers ─────────────────────────────────────────────────────────────────

/**
 * Chebyshev distance between two grid positions.
 * @param {number} c1
 * @param {number} r1
 * @param {number} c2
 * @param {number} r2
 * @returns {number}
 */
function chebyshevDistance(c1, r1, c2, r2) {
  return Math.max(Math.abs(c1 - c2), Math.abs(r1 - r2));
}

/**
 * Compute D&D-style attribute modifier.
 * @param {number} val
 * @returns {number}
 */
function getAttributeMod(val) {
  return Math.floor((val - 10) / 2);
}

// ─── CombatSystem ─────────────────────────────────────────────────────────────

const CombatSystem = {
  /** @type {object|null} */
  _state: null,

  /** @type {ReturnType<import('../utils/RNG.js').createRNG>|null} */
  _rng: null,

  /** @type {Array<{message: string, category: string, timestamp: number, round: number}>} */
  _log: [],

  /** @type {Array<function>} */
  _subscribers: [],

  // ── Public API ──────────────────────────────────────────────────────────────

  /**
   * Subscribe to combat events.
   * @param {function(string, object): void} fn — called with (eventType, data)
   * @returns {function} Unsubscribe function
   */
  subscribe(fn) {
    this._subscribers.push(fn);
    return () => {
      this._subscribers = this._subscribers.filter(s => s !== fn);
    };
  },

  /**
   * Emit an event to all subscribers.
   * @param {string} type
   * @param {object} [data]
   */
  _emit(type, data = {}) {
    for (const fn of this._subscribers) {
      try { fn(type, data); } catch (_e) { /* ignore subscriber errors */ }
    }
  },

  /**
   * Start a new combat encounter.
   * @param {object[]} partyChars — Array of character objects from CharacterSystem
   * @param {object[]} enemies — Array of enemy instances from EnemySystem
   * @param {object} [options]
   * @param {number} [options.seed]
   * @param {string} [options.environment='forest']
   * @param {number} [options.regionLevel=1]
   * @returns {object} Initial combat state
   */
  startCombat(partyChars, enemies, options = {}) {
    const seed = options.seed ?? Date.now();
    this._rng = createRNG(seed);
    this._log = [];

    const combatants = new Map();

    // Separate companions from regular party characters.
    // Companions have isCompanion=true (wolves, bears, skeletons).
    const regularChars = partyChars.filter(c => !c.isCompanion);
    const companions   = partyChars.filter(c => c.isCompanion);

    // Add regular party characters — cols 0-3, rows 0-1
    regularChars.forEach((char, idx) => {
      const c = this._wrapCharacter(char, idx);
      c.col = Math.min(idx, 3);
      c.row = Math.floor(idx / 4);
      combatants.set(c.id, c);
    });

    // Add companions — placed in party cols after regular members.
    // Companions use simple AI: attack nearest enemy after their caster acts.
    companions.forEach((companion, idx) => {
      const offset = regularChars.length + idx;
      const c = this._wrapCompanion(companion, offset);
      c.col = Math.min(offset % 4, 3);
      c.row = Math.floor(offset / 4) % GRID_ROWS;
      combatants.set(c.id, c);
    });

    // Add enemies — place in right 4 cols
    enemies.forEach((enemy, idx) => {
      const c = this._wrapEnemy(enemy);
      c.col = 4 + (idx % 4);
      c.row = Math.floor(idx / 4) % GRID_ROWS;
      combatants.set(c.id, c);
    });

    // Roll initiative
    const turnOrder = this._rollInitiative([...combatants.values()]);

    // Capture weather modifiers at combat start
    const weatherSnapshot = (() => {
      try { return WeatherSystem.getCurrentWeather(); } catch (_) { return null; }
    })();
    const weatherBlizzard = weatherSnapshot?.weather === 'blizzard';
    const weatherStorm    = weatherSnapshot?.weather === 'stormy';
    const weatherFoggy    = weatherSnapshot?.weather === 'foggy';

    if (weatherSnapshot) {
      DebugLog.info(
        `[combat] Weather at combat start: ${weatherSnapshot.weather} ` +
        `(season=${weatherSnapshot.season}); ` +
        `blizzard=${weatherBlizzard} storm=${weatherStorm} foggy=${weatherFoggy}`
      );
    }

    this._state = {
      id: `combat_${Date.now()}`,
      active: true,
      round: 1,
      turnIndex: 0,
      turnOrder,
      combatants,
      environment: options.environment ?? 'forest',
      regionLevel: options.regionLevel ?? 1,
      phase: 'player_turn',
      actionTaken: false,
      moveTaken: false,
      seed,
      // Weather modifiers active for this combat
      weatherBlizzard,  // move also costs action token
      weatherStorm,     // ranged attacks have +20% miss chance
      weatherFoggy,     // enemies had +15% initiative (applied during rollInitiative)
    };

    this._updatePhase();
    this.log(`Combat started — ${partyChars.length} heroes vs ${enemies.length} enemies`, 'system');
    DebugLog.info(`[combat] startCombat; party=${partyChars.length} enemies=${enemies.length} seed=${seed}`);

    this._emit('combat:start', { state: this._state });
    return this._state;
  },

  /**
   * Return the current combat state (or null if no combat is active).
   * @returns {object|null}
   */
  getState() {
    return this._state;
  },

  /**
   * Whether a combat is currently running.
   * @returns {boolean}
   */
  isActive() {
    return this._state?.active === true;
  },

  /**
   * Get the combatant whose turn it currently is.
   * @returns {object|null}
   */
  getCurrentCombatant() {
    if (!this._state) return null;
    const id = this._state.turnOrder[this._state.turnIndex];
    return this._state.combatants.get(id) ?? null;
  },

  /**
   * Execute a Move action for the current combatant.
   * @param {number} toCol
   * @param {number} toRow
   * @returns {{ success: boolean, message: string, events?: object[] }}
   */
  executeMove(toCol, toRow) {
    if (!this._canAct()) return { success: false, message: 'Cannot act now.' };
    const cur = this.getCurrentCombatant();
    if (!cur) return { success: false, message: 'No active combatant.' };
    if (this._state.moveTaken) return { success: false, message: 'Already moved this turn.' };

    // Validate target tile
    if (toCol < 0 || toCol >= GRID_COLS || toRow < 0 || toRow >= GRID_ROWS) {
      return { success: false, message: 'Out of bounds.' };
    }
    // Party can only move in cols 0-3; enemies in cols 4-7
    const validCols = cur.isPlayer ? PARTY_COLS : ENEMY_COLS;
    if (!validCols.includes(toCol)) return { success: false, message: 'Cannot move to that column.' };
    // Check tile occupied
    if (this._getTileOccupant(toCol, toRow)) return { success: false, message: 'Tile occupied.' };

    const fromCol = cur.col;
    const fromRow = cur.row;
    cur.col = toCol;
    cur.row = toRow;
    this._state.moveTaken = true;

    // Blizzard weather: moving is exhausting — it also consumes the action token
    if (this._state.weatherBlizzard) {
      this._state.actionTaken = true;
      this.log(`${cur.name} struggles through the blizzard — no action remaining.`, 'weather');
    }

    this.log(`${cur.name} moves (${fromCol},${fromRow}) -> (${toCol},${toRow})`, 'move');
    this._emit('combat:move', { combatantId: cur.id, from: { col: fromCol, row: fromRow }, to: { col: toCol, row: toRow } });
    return { success: true, message: 'Moved.', events: [{ type: 'move', id: cur.id }] };
  },

  /**
   * Execute an Attack action against a target.
   * @param {string} targetId
   * @returns {{ success: boolean, message: string, outcome?: string, damage?: number }}
   */
  executeAttack(targetId) {
    if (!this._canAct()) return { success: false, message: 'Cannot act now.' };
    if (this._state.actionTaken) return { success: false, message: 'Action already taken this turn.' };
    const cur = this.getCurrentCombatant();
    if (!cur) return { success: false, message: 'No active combatant.' };
    const target = this._state.combatants.get(targetId);
    if (!target) return { success: false, message: 'Target not found.' };
    if (!target.isConscious) return { success: false, message: 'Target is already down.' };
    if (cur.isPlayer === target.isPlayer) return { success: false, message: 'Cannot attack ally.' };

    const result = this._resolveAttack(cur, target);
    this._state.actionTaken = true;

    this._emit('combat:attack', { attackerId: cur.id, targetId, result });

    // M22: emit granular visual feedback events with grid position
    const targetPos = { col: target.col, row: target.row };
    if (result.outcome === 'miss' || result.outcome === 'dodge') {
      this._emit('combat:miss', { target, targetId, position: targetPos });
    } else {
      const isCrit = result.outcome === 'crit';
      this._emit('combat:hit', { target, targetId, damage: result.damage, isCrit, position: targetPos });
    }

    this._checkCombatEndInternal();
    return { ...result, success: true };
  },

  /**
   * Execute a Skill action.
   * @param {string} treeId
   * @param {string} skillId
   * @param {string|null} [primaryTargetId]
   * @returns {{ success: boolean, message: string, events?: object[] }}
   */
  executeSkill(treeId, skillId, primaryTargetId = null) {
    if (!this._canAct()) return { success: false, message: 'Cannot act now.' };
    if (this._state.actionTaken) return { success: false, message: 'Action already taken.' };
    const cur = this.getCurrentCombatant();
    if (!cur) return { success: false, message: 'No active combatant.' };

    const skill = SkillSystem.getSkillById(treeId, skillId);
    if (!skill) return { success: false, message: 'Unknown skill.' };

    const skillLevel = cur.skills?.[treeId]?.[skillId] ?? 1;

    // Check mana
    const manaCost = skill.manaCost ?? 0;
    if (cur.mana < manaCost) return { success: false, message: 'Not enough mana.' };

    // Check cooldown
    if ((cur.skillCooldowns[skillId] ?? 0) > 0) {
      return { success: false, message: `Skill on cooldown (${cur.skillCooldowns[skillId]} turns).` };
    }

    if (skill.isPassive) {
      return { success: false, message: 'Passive skills cannot be activated.' };
    }

    // Deduct mana, set cooldown
    cur.mana = Math.max(0, cur.mana - manaCost);
    if ((skill.cooldown ?? 0) > 0) cur.skillCooldowns[skillId] = skill.cooldown;

    // Determine target combatant objects (SkillExecutor works on objects, not IDs)
    const targetIds = this._resolveSkillTargets(skill, cur, primaryTargetId);
    const targetCombatants = targetIds
      .map(tid => this._state.combatants.get(tid))
      .filter(t => t != null);

    // Delegate execution to SkillExecutor
    const executorEvents = SkillExecutor.execute(skill, cur, targetCombatants, this.getState(), this._rng, skillLevel);

    // Apply executor events to combat state
    const events = [];
    for (const ev of executorEvents) {
      switch (ev.type) {
        case 'damage': {
          const target = this._state.combatants.get(ev.target);
          if (target && target.isConscious) {
            const dmg = this._applyResistance(ev.amount, ev.damageType ?? 'physical', target);
            target.hp = Math.max(0, target.hp - dmg);
            if (target.hp === 0) this._makeUnconscious(target);
            this.log(ev.message ?? `${cur.name} deals ${dmg} dmg to ${target.name}.`, 'skill');
            events.push({ type: 'damage', targetId: ev.target, amount: dmg, damageType: ev.damageType, isCrit: ev.isCrit });
          }
          break;
        }
        case 'heal': {
          const target = this._state.combatants.get(ev.target);
          if (target && target.isConscious) {
            target.hp = Math.min(target.maxHP, target.hp + ev.amount);
            this.log(ev.message ?? `${target.name} recovers ${ev.amount} HP.`, 'skill');
            events.push({ type: 'heal', targetId: ev.target, amount: ev.amount });
            // M22: emit visual feedback event with grid position
            this._emit('combat:heal', { target, targetId: ev.target, amount: ev.amount, position: { col: target.col, row: target.row } });
          }
          break;
        }
        case 'shield': {
          const target = this._state.combatants.get(ev.target);
          if (target && target.isConscious) {
            // Store shield HP on the combatant for future damage absorption
            target.shieldHP = (target.shieldHP ?? 0) + ev.amount;
            this.log(ev.message ?? `${target.name} gains a ${ev.amount} HP shield.`, 'skill');
            events.push({ type: 'shield', targetId: ev.target, amount: ev.amount });
          }
          break;
        }
        case 'status': {
          const target = this._state.combatants.get(ev.target);
          if (target) {
            this.applyStatus(target, ev.statusId, ev.source);
            events.push({ type: 'status', targetId: ev.target, statusId: ev.statusId });
            // M22: emit visual feedback event with grid position
            this._emit('combat:status', { target, targetId: ev.target, statusId: ev.statusId, statusName: ev.statusId, position: { col: target.col, row: target.row } });
          }
          break;
        }
        case 'consume_crit_status': {
          const target = this._state.combatants.get(ev.target);
          if (target) {
            target.statusEffects = target.statusEffects.filter(
              e => e.id !== 'marked' && e.id !== 'coup_de_grace'
            );
          }
          break;
        }
        case 'summon': {
          // Emit summon event — scene layer handles companion placement
          this.log(ev.message ?? `${cur.name} summons a ${ev.companionType}.`, 'skill');
          events.push({ type: 'summon', casterId: cur.id, companionType: ev.companionType, skillLevel: ev.skillLevel });
          break;
        }
        case 'resurrect': {
          const target = this._state.combatants.get(ev.target);
          if (target && !target.isConscious) {
            target.isConscious = true;
            target.hp = Math.max(1, Math.floor(target.maxHP * (ev.hpFraction ?? 0.5)));
            this.log(ev.message ?? `${target.name} is resurrected!`, 'skill');
            events.push({ type: 'resurrect', targetId: ev.target });
          }
          break;
        }
        case 'dispel': {
          const target = this._state.combatants.get(ev.target);
          if (target) {
            target.statusEffects = target.statusEffects.filter(e => e.id !== ev.removedStatusId);
            this.log(ev.message ?? `${target.name}: ${ev.removedStatusId} dispelled.`, 'skill');
            events.push({ type: 'dispel', targetId: ev.target, statusId: ev.removedStatusId });
          }
          break;
        }
        case 'aura': {
          cur.activeAura = ev.skillId;
          this.log(ev.message ?? `${cur.name} activates aura: ${skill.name}.`, 'skill');
          events.push({ type: 'aura', casterId: cur.id, skillId: ev.skillId });
          break;
        }
        // 'message' events are informational only
        default:
          break;
      }
    }

    // If the skill itself is an aura but SkillExecutor didn't emit an aura event
    // (e.g. aura with no other effects), handle it here as a fallback.
    if (skill.isAura && !executorEvents.some(e => e.type === 'aura')) {
      cur.activeAura = skillId;
      this.log(`${cur.name} activates aura: ${skill.name}`, 'skill');
    }

    this._state.actionTaken = true;
    this._emit('combat:skill', { casterId: cur.id, skillId, treeId, targetIds, events });
    this._checkCombatEndInternal();
    return { success: true, message: `Used ${skill.name}.`, events };
  },

  /**
   * Execute a Defend action — increases defense until next turn.
   * @returns {{ success: boolean, message: string }}
   */
  executeDefend() {
    if (!this._canAct()) return { success: false, message: 'Cannot act now.' };
    if (this._state.actionTaken) return { success: false, message: 'Action already taken.' };
    const cur = this.getCurrentCombatant();
    if (!cur) return { success: false, message: 'No active combatant.' };

    cur.isDefending = true;
    this._state.actionTaken = true;
    this.log(`${cur.name} takes a defensive stance.`, 'action');
    this._emit('combat:defend', { combatantId: cur.id });
    return { success: true, message: 'Defending.' };
  },

  /**
   * Execute a Pass — end action without doing anything.
   * @returns {{ success: boolean, message: string }}
   */
  executePass() {
    if (!this._canAct()) return { success: false, message: 'Cannot act now.' };
    const cur = this.getCurrentCombatant();
    if (!cur) return { success: false, message: 'No active combatant.' };

    this._state.actionTaken = true;
    this.log(`${cur.name} passes.`, 'action');
    this._emit('combat:pass', { combatantId: cur.id });
    return { success: true, message: 'Passed.' };
  },

  /**
   * Advance to the next combatant's turn.
   * @returns {object|null} The combatant whose turn it now is
   */
  nextTurn() {
    if (!this._state?.active) return null;
    const cur = this.getCurrentCombatant();

    // Tick skill cooldowns and reset defending flag
    if (cur) {
      for (const skillId of Object.keys(cur.skillCooldowns)) {
        cur.skillCooldowns[skillId] = Math.max(0, cur.skillCooldowns[skillId] - 1);
      }
      cur.isDefending = false;
    }

    // Advance index
    this._state.turnIndex = (this._state.turnIndex + 1) % this._state.turnOrder.length;

    // Skip dead/unconscious combatants
    let safetyCounter = 0;
    while (safetyCounter < 32) {
      const next = this.getCurrentCombatant();
      if (next && next.isConscious) break;
      this._state.turnIndex = (this._state.turnIndex + 1) % this._state.turnOrder.length;
      safetyCounter++;
    }

    // New round?
    if (this._state.turnIndex === 0) {
      this._state.round++;
      this.log(`--- Round ${this._state.round} ---`, 'system');
      this._emit('combat:new_round', { round: this._state.round });
    }

    // Reset per-turn flags
    this._state.actionTaken = false;
    this._state.moveTaken = false;

    const next = this.getCurrentCombatant();

    // Process start-of-turn status effects
    if (next) this.processTurnStart(next);

    this._updatePhase();
    this._emit('combat:turn_start', { combatantId: next?.id });
    return next;
  },

  /**
   * Check whether combat has ended.
   * @returns {{ over: boolean, winner: 'party'|'enemies'|null }}
   */
  checkCombatEnd() {
    if (!this._state) return { over: false, winner: null };
    const allParty   = [...this._state.combatants.values()].filter(c => c.isPlayer);
    const allEnemies = [...this._state.combatants.values()].filter(c => !c.isPlayer);
    const partyAlive   = allParty.some(c => c.isConscious);
    const enemiesAlive = allEnemies.some(c => c.isConscious);
    if (!partyAlive)   return { over: true, winner: 'enemies' };
    if (!enemiesAlive) return { over: true, winner: 'party' };
    return { over: false, winner: null };
  },

  /**
   * End the current combat, distribute XP and loot.
   * @returns {{ xp: number, loot: object[], levelUps: object[] }}
   */
  endCombat() {
    if (!this._state) return { xp: 0, loot: [], levelUps: [] };
    const state = this._state;
    state.active = false;

    const deadEnemies = [...state.combatants.values()].filter(c => !c.isPlayer && !c.isConscious);
    let totalXP = deadEnemies.reduce((s, e) => s + (e.xpReward ?? 10), 0);

    // Collect loot drops from all defeated enemies
    const loot = [];
    for (const enemy of deadEnemies) {
      const drops = EnemySystem.rollLoot(enemy, this._rng);
      loot.push(...drops.items);
    }

    // M31: Award loot table rewards for defeated enemies via LootSystem.
    // Use the first dead enemy's base id to pick the correct table.
    // Each unique enemy type rolls its own table independently.
    {
      const worldState =
        typeof window !== 'undefined' && window.__worldState
          ? window.__worldState
          : null;
      const usedTables = new Set();
      for (const enemy of deadEnemies) {
        const tableId = LootSystem.getLootForEnemy(enemy.baseId ?? enemy.id);
        if (!usedTables.has(tableId)) {
          usedTables.add(tableId);
          LootSystem.awardLoot(worldState, tableId, this._rng);
        }
      }
    }

    // XP split among conscious party members
    const survivors = [...state.combatants.values()].filter(c => c.isPlayer && c.isConscious);
    const xpEach = survivors.length > 0 ? Math.floor(totalXP / survivors.length) : 0;

    const levelUps = [];
    for (const s of survivors) {
      if (s.sourceChar) {
        const prevLevel = s.sourceChar.level;
        CharacterSystem.grantXP(s.sourceChar, xpEach);
        if (s.sourceChar.level > (s.startLevel ?? prevLevel)) {
          levelUps.push({ charId: s.id, name: s.name, newLevel: s.sourceChar.level });
        }
      }
    }

    // M22: emit XP event for floating text
    if (xpEach > 0) {
      this._emit('combat:xp', { amount: xpEach, survivors: survivors.map(s => ({ id: s.id, name: s.name, col: s.col, row: s.row })) });
    }

    // M22: emit level-up events for each character that levelled up
    for (const lu of levelUps) {
      const survivor = survivors.find(s => s.id === lu.charId);
      const pos = survivor ? { col: survivor.col, row: survivor.row } : null;
      this._emit('character:levelup', { char: lu, charId: lu.charId, name: lu.name, newLevel: lu.newLevel, position: pos });
    }

    this.log(`Combat ended — ${survivors.length} survivors, ${xpEach} XP each`, 'system');
    DebugLog.info(`[combat] endCombat; xp=${xpEach} loot=${loot.length} levelUps=${levelUps.length}`);
    this._emit('combat:end', { winner: this.checkCombatEnd().winner, xp: xpEach, loot, levelUps });

    this._state = null;
    return { xp: xpEach, loot, levelUps };
  },

  /**
   * Apply a status effect to a combatant.
   * Handles stacking, duration refresh, and combo triggers.
   * @param {object} combatant
   * @param {string} statusId
   * @param {string|null} [sourceId]
   */
  applyStatus(combatant, statusId, sourceId = null) {
    const def = STATUS_EFFECTS.find(s => s.id === statusId);
    if (!def) return;

    const existing = combatant.statusEffects.find(s => s.id === statusId);
    if (existing) {
      if (def.stackable && existing.stacks < (def.maxStacks ?? 10)) {
        existing.stacks++;
        existing.duration = def.duration ?? 3;
      } else {
        existing.duration = def.duration ?? 3; // refresh duration
      }
    } else {
      combatant.statusEffects.push({
        id: statusId,
        duration: def.duration ?? 3,
        sourceId,
        stacks: 1,
      });
    }

    // Check combo triggers
    this._checkStatusCombos(combatant);
    this.log(`${combatant.name} is affected by ${def.name}`, 'status');
  },

  /**
   * Process start-of-turn status effects (tick damage, duration reduction, expiry).
   * @param {object} combatant
   */
  processTurnStart(combatant) {
    const toRemove = [];
    for (const effect of combatant.statusEffects) {
      const def = STATUS_EFFECTS.find(s => s.id === effect.id);
      if (!def) { toRemove.push(effect.id); continue; }

      // Tick heal (e.g. regenerating)
      if (def.tickHeal && combatant.isConscious) {
        const heal = def.tickHeal;
        combatant.hp = Math.min(combatant.maxHP, combatant.hp + heal);
        this.log(`${combatant.name} regenerates ${heal} HP from ${def.name}`, 'status');
      }

      // Tick damage
      if (def.tickDamage && combatant.isConscious) {
        const dmg = def.tickDamage * (effect.stacks ?? 1);
        combatant.hp = Math.max(0, combatant.hp - dmg);
        if (combatant.hp === 0) this._makeUnconscious(combatant);
        this.log(`${combatant.name} takes ${dmg} ${def.damageType ?? ''} dmg from ${def.name}`, 'status');
      }

      // Tick duration (skip string-valued durations like "combat" or "until_triggered")
      if (typeof effect.duration === 'number') {
        effect.duration--;
        if (effect.duration <= 0) {
          toRemove.push(effect.id);
          this.log(`${combatant.name}: ${def.name} expired`, 'status');
        }
      }
    }
    combatant.statusEffects = combatant.statusEffects.filter(e => !toRemove.includes(e.id));
  },

  /**
   * Add an entry to the combat log and emit it as an event.
   * @param {string} message
   * @param {string} [category='combat']
   */
  log(message, category = 'combat') {
    const entry = {
      message,
      category,
      timestamp: Date.now(),
      round: this._state?.round ?? 0,
    };
    this._log.push(entry);
    if (this._log.length > 200) this._log.shift();
    DebugLog.event(`[${category}] ${message}`);
    this._emit('combat:log', entry);
  },

  /**
   * Return the last N combat log entries.
   * @param {number} [n=20]
   * @returns {Array<{message: string, category: string, timestamp: number, round: number}>}
   */
  getLog(n = 20) {
    return this._log.slice(-n);
  },

  // ── Enemy AI ─────────────────────────────────────────────────────────────────

  /**
   * Execute an AI-controlled combatant's turn.
   * Handles both enemy profiles (aggressive, defensive, ranged) and
   * the companion AI profile (attacks nearest enemy after summoner).
   *
   * @param {object} combatant
   */
  executeEnemyTurn(combatant) {
    const profile = combatant.aiProfile ?? 'aggressive';

    // Companion AI — attacks nearest enemy (opposite side)
    if (combatant.isCompanion) {
      this._executeCompanionTurn(combatant);
      return;
    }

    // Find all conscious player targets
    const players = [...this._state.combatants.values()].filter(c => c.isPlayer && c.isConscious);
    if (!players.length) { this.executePass(); return; }

    // Default: target nearest
    let target = players.reduce((best, p) => {
      const dist     = chebyshevDistance(combatant.col, combatant.row, p.col, p.row);
      const bestDist = chebyshevDistance(combatant.col, combatant.row, best.col, best.row);
      return dist < bestDist ? p : best;
    });

    // Aggressive: prefer lowest-HP target
    if (profile === 'aggressive') {
      target = players.reduce((a, b) => a.hp < b.hp ? a : b);
    }

    // Try to move closer if not adjacent
    const dist = chebyshevDistance(combatant.col, combatant.row, target.col, target.row);
    if (!this._state.moveTaken && dist > 1) {
      const dc = Math.sign(target.col - combatant.col);
      const dr = Math.sign(target.row - combatant.row);
      const newCol = combatant.col + dc;
      const newRow = combatant.row + dr;
      if (!this._getTileOccupant(newCol, newRow)) {
        this.executeMove(newCol, newRow);
      }
    }

    // Attack if in range
    const newDist = chebyshevDistance(combatant.col, combatant.row, target.col, target.row);
    if (newDist <= 2 && !this._state.actionTaken) {
      this.executeAttack(target.id);
    } else if (!this._state.actionTaken) {
      this.executePass();
    }
  },

  /**
   * Execute a companion's AI turn.
   * Companions (wolf, bear, skeleton) attack the nearest conscious enemy.
   * They do not use skills (except skeletons with inherited Death tree skills,
   * handled by future extension). No defensive repositioning logic.
   *
   * @param {object} companion
   */
  _executeCompanionTurn(companion) {
    const enemies = [...this._state.combatants.values()].filter(c => !c.isPlayer && c.isConscious);
    if (!enemies.length) { this.executePass(); return; }

    // Target the nearest enemy
    const target = enemies.reduce((best, e) => {
      const dist     = chebyshevDistance(companion.col, companion.row, e.col, e.row);
      const bestDist = chebyshevDistance(companion.col, companion.row, best.col, best.row);
      return dist < bestDist ? e : best;
    });

    // Move toward target if not already adjacent
    const dist = chebyshevDistance(companion.col, companion.row, target.col, target.row);
    if (!this._state.moveTaken && dist > 1) {
      const dc = Math.sign(target.col - companion.col);
      const dr = Math.sign(target.row - companion.row);
      const newCol = companion.col + dc;
      const newRow = companion.row + dr;
      if (!this._getTileOccupant(newCol, newRow)) {
        this.executeMove(newCol, newRow);
      }
    }

    const newDist = chebyshevDistance(companion.col, companion.row, target.col, target.row);
    if (newDist <= 1 && !this._state.actionTaken) {
      this.executeAttack(target.id);
    } else if (!this._state.actionTaken) {
      this.executePass();
    }
  },

  // ── Private helpers ──────────────────────────────────────────────────────────

  /**
   * Wrap a party character into a combat combatant object.
   * @param {object} char
   * @param {number} idx — Party index (0-based)
   * @returns {object}
   */
  _wrapCharacter(char, idx) {
    return {
      id: char.id,
      name: char.name,
      isPlayer: true,
      playerId: idx + 1,
      col: 0, row: 0,
      hp: char.hp ?? char.maxHP,
      maxHP: char.maxHP,
      mana: char.mana ?? char.maxMana,
      maxMana: char.maxMana,
      statusEffects: [],
      isDefending: false,
      isConscious: (char.hp ?? char.maxHP) > 0,
      initiative: 0,
      attributes: { ...char.attributes },
      equipment: char.equipment ?? {},
      skills: char.skills ?? {},
      skillTrees: char.skillTrees ?? [],
      skillCooldowns: {},
      startLevel: char.level,
      xpReward: 0,
      loot: [],
      sourceChar: char,
    };
  },

  /**
   * Wrap an enemy instance into a combat combatant object.
   * @param {object} enemy
   * @returns {object}
   */
  _wrapEnemy(enemy) {
    return {
      id: enemy.id,
      name: enemy.name,
      isPlayer: false,
      isEnemy: true,
      playerId: null,
      col: 0, row: 0,
      hp: enemy.hp ?? enemy.maxHP,
      maxHP: enemy.maxHP ?? enemy.hp,
      mana: enemy.mana ?? 0,
      maxMana: enemy.maxMana ?? 0,
      statusEffects: [],
      isDefending: false,
      isConscious: true,
      initiative: 0,
      attributes: { ...enemy.attributes },
      equipment: {},
      skills: {},
      skillTrees: [],
      skillCooldowns: {},
      xpReward: enemy.xpReward ?? 10,
      loot: enemy.loot ?? [],
      aiProfile: enemy.aiProfile ?? 'aggressive',
      weaponDamage: enemy.weaponDamage ?? { min: 5, max: 9 },
      armor: enemy.armor ?? 0,
      sourceChar: null,
    };
  },

  /**
   * Wrap a companion character into a combat combatant object.
   *
   * Companions (wolves, bears, skeletons) occupy party-side formation slots,
   * act as player-aligned combatants, and use simple AI: attack the nearest
   * enemy. They have no inventory and limited (or no) skills. Skeletons may
   * inherit Death tree skills from their summoner.
   *
   * @param {object} companion — companion character data (isCompanion=true)
   * @param {number} slotIndex — formation slot index (used for initial placement)
   * @returns {object}
   */
  _wrapCompanion(companion, slotIndex) {
    return {
      id: companion.id,
      name: companion.name,
      isPlayer: true,       // allies — occupies party grid side
      isCompanion: true,
      playerId: null,       // companions don't belong to a specific human player
      col: 0, row: 0,
      hp: companion.hp ?? companion.maxHP,
      maxHP: companion.maxHP ?? companion.hp,
      mana: 0,
      maxMana: 0,
      statusEffects: [],
      isDefending: false,
      isConscious: (companion.hp ?? companion.maxHP) > 0,
      initiative: 0,
      attributes: { ...(companion.attributes ?? { might: 12, agility: 12, intellect: 8, wisdom: 8, endurance: 12, presence: 8 }) },
      equipment: {},
      // Skeletons may inherit their summoner's Death tree skills; others have none.
      skills: companion.inheritedSkills ?? {},
      skillTrees: companion.inheritedSkillTrees ?? [],
      skillCooldowns: {},
      xpReward: 0,
      loot: [],
      aiProfile: companion.aiProfile ?? 'companion',
      weaponDamage: companion.weaponDamage ?? { min: 4, max: 8 },
      armor: companion.armor ?? 0,
      sourceChar: companion.sourceChar ?? null,
      summonerId: companion.summonerId ?? null,
    };
  },

  /**
   * Roll initiative for all combatants and return a sorted turn order.
   * @param {object[]} combatants
   * @returns {string[]} Ordered array of combatant IDs
   */
  _rollInitiative(combatants) {
    const rng = this._rng;
    const foggyWeather = this._state?.weatherFoggy ?? false;
    const rolled = combatants.map(c => {
      const agiMod = getAttributeMod(c.attributes?.agility ?? 10);
      let roll = rollD20(rng) + agiMod;

      // Foggy weather: enemies get a +15% initiative surge (rounded).
      // This simulates their familiarity with concealment.
      if (foggyWeather && !c.isPlayer) {
        roll = Math.round(roll * 1.15);
      }

      c.initiative = roll;
      return { id: c.id, roll };
    });
    rolled.sort((a, b) => b.roll - a.roll || a.id.localeCompare(b.id));
    // Log is not yet available before state is assigned; defer or use DebugLog directly
    const names = rolled.map(r => {
      const name = this._state?.combatants?.get(r.id)?.name ?? r.id;
      return `${name}(${r.roll})`;
    }).join(', ');
    DebugLog.event(`[combat] Initiative: ${names}`);
    return rolled.map(r => r.id);
  },

  /**
   * Resolve a basic attack from attacker to target.
   * @param {object} attacker
   * @param {object} target
   * @returns {{ outcome: string, roll: number, dc: number, damage: number, targetId: string }}
   */
  _resolveAttack(attacker, target) {
    const rng = this._rng;
    const atkAgiMod = getAttributeMod(attacker.attributes?.agility ?? 10);
    const defAgiMod = getAttributeMod(target.attributes?.agility ?? 10);

    const roll = rollD20(rng) + atkAgiMod;
    const dc = 10 + defAgiMod + (target.armor ?? 0) + (target.isDefending ? 3 : 0);

    // Storm weather: ranged attacks have an additional 20% miss chance.
    // An attack is considered ranged when the attacker's attackType is 'ranged'
    // or the Chebyshev grid distance between attacker and target is > 2.
    const isRangedAttack =
      attacker.attackType === 'ranged' ||
      chebyshevDistance(attacker.col, attacker.row, target.col, target.row) > 2;

    const stormForcedMiss =
      this._state?.weatherStorm && isRangedAttack && Math.random() < 0.20;

    if (stormForcedMiss) {
      this.log(
        `${attacker.name}'s ranged attack on ${target.name} is blown off course by the storm! (miss)`,
        'weather'
      );
      return { outcome: 'miss', roll, dc, damage: 0, targetId: target.id };
    }

    let outcome, multiplier;
    if (roll >= dc + 10)      { outcome = 'crit';     multiplier = 1.5; }
    else if (roll >= dc)      { outcome = 'hit';      multiplier = 1.0; }
    else if (roll >= dc - 5)  { outcome = 'glancing'; multiplier = 0.5; }
    else                      { outcome = 'miss';     multiplier = 0;   }

    // Damage formula: base_damage + might_modifier - target_defense, then apply hit multiplier.
    const targetDefense = target.armor ?? 0;
    const baseDmg = Math.max(1, this._getBaseDamage(attacker) - targetDefense);
    const rawDmg  = Math.max(multiplier > 0 ? 1 : 0, Math.round(baseDmg * multiplier));
    const dmg     = this._applyResistance(rawDmg, 'physical', target);

    if (dmg > 0) {
      target.hp = Math.max(0, target.hp - dmg);
      if (target.hp === 0) this._makeUnconscious(target);
    }

    const msg = outcome === 'miss'
      ? `${attacker.name} attacks ${target.name}: roll=${roll} dc=${dc} -> Miss`
      : `${attacker.name} attacks ${target.name}: roll=${roll} dc=${dc} -> ${outcome}! ${dmg} dmg`;
    this.log(msg, 'attack');

    return { outcome, roll, dc, damage: dmg, targetId: target.id };
  },

  /**
   * Get the base damage for a combatant (weapon or unarmed), including might modifier.
   * Formula: base_damage + might_modifier (defense subtracted in _resolveAttack).
   * @param {object} combatant
   * @returns {number}
   */
  _getBaseDamage(combatant) {
    const mightMod = getAttributeMod(combatant.attributes?.might ?? 10);
    if (combatant.weaponDamage) {
      return rollRange(this._rng, combatant.weaponDamage.min, combatant.weaponDamage.max) + mightMod;
    }
    // Player — use equipped weapon
    const weapon = combatant.equipment?.weapon;
    if (weapon?.damage) {
      return rollRange(this._rng, weapon.damage.min ?? 5, weapon.damage.max ?? 10) + mightMod;
    }
    // Unarmed
    return Math.max(1, 3 + mightMod);
  },

  /**
   * Get the min/max damage range for a combatant against a target.
   * Formula: base_damage_range + might_modifier - target_defense (min 1).
   * @param {object} attacker
   * @param {object} target
   * @returns {{ min: number, max: number }}
   */
  getDamageRange(attacker, target) {
    const mightMod = getAttributeMod(attacker.attributes?.might ?? 10);
    const targetDefense = target.armor ?? 0;

    let baseMin, baseMax;
    if (attacker.weaponDamage) {
      baseMin = attacker.weaponDamage.min;
      baseMax = attacker.weaponDamage.max;
    } else {
      const weapon = attacker.equipment?.weapon;
      if (weapon?.damage) {
        baseMin = weapon.damage.min ?? 5;
        baseMax = weapon.damage.max ?? 10;
      } else {
        baseMin = Math.max(1, 3 + mightMod);
        baseMax = Math.max(1, 3 + mightMod);
      }
    }

    return {
      min: Math.max(1, baseMin + mightMod - targetDefense),
      max: Math.max(1, baseMax + mightMod - targetDefense),
    };
  },

  /**
   * Apply damage resistance for a damage type. Placeholder for future resistance system.
   * @param {number} dmg
   * @param {string} _type
   * @param {object} _target
   * @returns {number}
   */
  _applyResistance(dmg, _type, _target) {
    return Math.max(0, dmg);
  },

  /**
   * Resolve all targets for a skill, handling AoE shapes and targeting types.
   * @param {object} skill
   * @param {object} caster
   * @param {string|null} primaryTargetId
   * @returns {string[]} Array of combatant IDs to affect
   */
  _resolveSkillTargets(skill, caster, primaryTargetId) {
    const state = this._state;
    const shape = SkillSystem.getAoEShape(skill);

    if (skill.targetingType === 'self') {
      return [caster.id];
    }
    if (skill.targetingType === 'aoe_all_enemies') {
      return [...state.combatants.values()]
        .filter(c => c.isPlayer !== caster.isPlayer && c.isConscious)
        .map(c => c.id);
    }
    if (skill.targetingType === 'aoe_all_allies') {
      return [...state.combatants.values()]
        .filter(c => c.isPlayer === caster.isPlayer && c.isConscious && c.id !== caster.id)
        .map(c => c.id);
    }
    if (!primaryTargetId) return [];
    if (!shape || shape.length === 0) return [primaryTargetId];

    // Map AoE shape offsets to actual combatant IDs
    const primary = state.combatants.get(primaryTargetId);
    if (!primary) return [primaryTargetId];

    const targets = new Set([primaryTargetId]);
    for (const { dx, dy } of shape) {
      if (dx === 0 && dy === 0) continue;
      const tc = primary.col + dx;
      const tr = primary.row + dy;
      const occ = this._getTileOccupant(tc, tr);
      if (occ && occ.isConscious && occ.isPlayer !== caster.isPlayer) {
        targets.add(occ.id);
      }
    }
    return [...targets];
  },

  /**
   * Find the occupant of a grid tile (conscious combatants only).
   * @param {number} col
   * @param {number} row
   * @returns {object|null}
   */
  _getTileOccupant(col, row) {
    if (!this._state) return null;
    for (const c of this._state.combatants.values()) {
      if (c.col === col && c.row === row && c.isConscious) return c;
    }
    return null;
  },

  /**
   * Mark a combatant as unconscious (defeated).
   * @param {object} combatant
   */
  _makeUnconscious(combatant) {
    combatant.isConscious = false;
    combatant.hp = 0;
    this.log(`${combatant.name} is defeated!`, 'death');
    this._emit('combat:defeated', { combatantId: combatant.id });
  },

  /**
   * Check and trigger any status combo reactions on a combatant.
   * @param {object} combatant
   */
  _checkStatusCombos(combatant) {
    const ids = new Set(combatant.statusEffects.map(e => e.id));
    for (const effect of [...combatant.statusEffects]) {
      const def = STATUS_EFFECTS.find(s => s.id === effect.id);
      if (!def?.combos) continue;
      for (const combo of def.combos) {
        if (combo.withStatus && ids.has(combo.withStatus)) {
          this.log(`${combatant.name}: ${combo.result} combo triggered!`, 'combo');
          if (combo.removesBoth) {
            combatant.statusEffects = combatant.statusEffects.filter(
              e => e.id !== effect.id && e.id !== combo.withStatus
            );
          }
          this.applyStatus(combatant, combo.result, null);
          break;
        }
      }
    }
  },

  /**
   * Update the combat phase based on the current combatant.
   */
  _updatePhase() {
    if (!this._state) return;
    const cur = this.getCurrentCombatant();
    this._state.phase = cur?.isPlayer ? 'player_turn' : 'enemy_turn';
  },

  /**
   * Whether the current combatant can take actions.
   * @returns {boolean}
   */
  _canAct() {
    return this._state?.active === true && !this._state.phase?.includes('resolution');
  },

  /**
   * Check if combat has ended after an action and update state accordingly.
   */
  _checkCombatEndInternal() {
    const { over, winner } = this.checkCombatEnd();
    if (over) {
      this._state.active = false;
      this._state.phase = winner === 'party' ? 'victory' : 'defeat';
      this.log(winner === 'party' ? 'Victory!' : 'Defeat...', 'system');
      this._emit('combat:over', { winner });
    }
  },
};

// ─── Debug exposure ───────────────────────────────────────────────────────────

if (typeof window !== 'undefined') {
  window.__combatSystem = CombatSystem;
}

export default CombatSystem;
