/**
 * FloatingText — Spawns animated floating text labels over the game UI.
 *
 * Uses absolutely-positioned HTML/CSS divs (not PixiJS Text) to stay
 * consistent with the HTML/CSS UI rules. Text floats upward and fades out
 * over 1.2 seconds then removes itself.
 *
 * Usage:
 *   FloatingText.spawn(x, y, text, type)
 *   // type: 'damage' | 'heal' | 'miss' | 'crit' | 'status' | 'xp'
 *
 * @module FloatingText
 */

import DebugLog from '../debug/DebugLog.js';

// ─── FloatingText ────────────────────────────────────────────────────────────

const FloatingText = {
  /** @type {HTMLElement|null} Container element for all floating text divs */
  _container: null,

  /**
   * Ensure the floating text container exists and is in the DOM.
   * Creates it if necessary and appends to #ui-overlay or body.
   * @returns {HTMLElement}
   */
  _ensureContainer() {
    if (this._container && document.contains(this._container)) {
      return this._container;
    }
    const existing = document.getElementById('floating-text-layer');
    if (existing) {
      this._container = existing;
      return this._container;
    }
    const el = document.createElement('div');
    el.id = 'floating-text-layer';
    el.className = 'floating-text-container';
    el.style.cssText = [
      'position:fixed',
      'inset:0',
      'pointer-events:none',
      'z-index:500',
      'overflow:hidden',
    ].join(';');
    const overlay = document.getElementById('ui-overlay');
    if (overlay) {
      overlay.appendChild(el);
    } else {
      document.body.appendChild(el);
    }
    this._container = el;
    return el;
  },

  /**
   * Spawn a floating text label at the given screen coordinates.
   *
   * @param {number} x         — screen X (pixels from left)
   * @param {number} y         — screen Y (pixels from top)
   * @param {string} text      — text to display
   * @param {'damage'|'heal'|'miss'|'crit'|'status'|'xp'} type
   */
  spawn(x, y, text, type = 'damage') {
    try {
      const container = this._ensureContainer();
      const el = document.createElement('div');

      // Map type to CSS class
      const classMap = {
        damage: 'ft-damage',
        heal:   'ft-heal',
        miss:   'ft-miss',
        crit:   'ft-crit',
        status: 'ft-status',
        xp:     'ft-xp',
      };
      const cls = classMap[type] ?? 'ft-damage';
      el.className = `floating-text ${cls}`;
      el.textContent = text;

      // Slight horizontal jitter to prevent overlapping stacked numbers
      const jitter = (Math.random() - 0.5) * 20;

      el.style.cssText = [
        'position:absolute',
        `left:${Math.round(x + jitter)}px`,
        `top:${Math.round(y)}px`,
        'transform:translateX(-50%)',
        'pointer-events:none',
        'white-space:nowrap',
        'z-index:10',
      ].join(';');

      container.appendChild(el);

      // Remove after animation completes
      el.addEventListener('animationend', () => {
        el.remove();
      }, { once: true });

      // Safety removal in case animationend doesn't fire (e.g. display:none)
      setTimeout(() => {
        if (el.parentNode) el.remove();
      }, 1600);

    } catch (e) {
      DebugLog.warn(`[combat] FloatingText.spawn error: ${e.message}`);
    }
  },
};

export default FloatingText;

// Expose on window for Playwright tests
if (typeof window !== 'undefined') {
  window.FloatingText = FloatingText;
}
