/**
 * SkillExecutor — Executes skill effects in a combat context.
 *
 * Called by CombatSystem.executeSkill() after validation, mana deduction,
 * and cooldown assignment. Returns an array of event objects describing
 * everything that happened so the caller can apply state changes and emit UI events.
 *
 * Skill definitions come from src/data/skill_trees.json. The data schema does NOT
 * use a nested `effect` object — effects are driven by the following top-level fields:
 *   - damageMultiplier  {number[]|null} — indexed by (skillLevel - 1)
 *   - damageSource      {"weapon"|"spell"|"both"}
 *   - applyStatus       {string[]} — status IDs to inflict on targets
 *   - targetingType     {string}  — already resolved to target IDs by CombatSystem
 *   - isAura            {boolean}
 *   - isShout           {boolean}
 *   - isPartySkill      {boolean}
 *
 * Healing is identified by treeId containing "holy" or "nature" AND a null/missing
 * damageMultiplier with `damageSource === "spell"` targeting allies — or explicitly
 * via a `healMultiplier` field added in future data. For now we use tree-level heuristics
 * and the `healingSkillIds` set below, which can be extended as needed.
 *
 * @module SkillExecutor
 */

import DebugLog from '../debug/DebugLog.js';

// ─── Stat → attribute key mapping ────────────────────────────────────────────

/** Which character attribute drives damage for each damage source type. */
const DAMAGE_STAT = {
  weapon: 'might',
  spell:  'intellect',
  both:   'might',    // hybrid: use might; future could blend both
};

// ─── Known healing skill IDs ──────────────────────────────────────────────────

/**
 * Skills whose damageMultiplier should be interpreted as a heal multiplier
 * rather than a damage multiplier. Identified by id (not treeId+skillId combo).
 * Extend this set as new healing skills are added to data.
 */
const HEAL_SKILL_IDS = new Set([
  'holy_heal',
  'holy_mass_heal',
  'holy_holy_nova',    // dual: heals allies, damages enemies
  'nature_herbal_remedy',
  'nature_regrowth',   // applies regenerating — no direct heal amount
]);

/**
 * Skills that apply a shield (shielded status) to the target.
 * These use damageMultiplier as a shield-amount multiplier.
 */
const SHIELD_SKILL_IDS = new Set([
  'holy_divine_shield',
]);

/**
 * Skills that summon companions. Resolved by CombatSystem; SkillExecutor
 * emits a summon event for downstream handling.
 */
const SUMMON_SKILL_IDS = new Set([
  'nature_summon_wolf',
  'nature_summon_bear',
  'death_raise_skeleton_warrior',
  'death_raise_skeleton_mage',
  'death_raise_skeleton_archer',
]);

/** Companion type mapping from skill ID. */
const SUMMON_TYPE_MAP = {
  nature_summon_wolf:          'wolf',
  nature_summon_bear:          'bear',
  death_raise_skeleton_warrior: 'skeleton_warrior',
  death_raise_skeleton_mage:    'skeleton_mage',
  death_raise_skeleton_archer:  'skeleton_archer',
};

// ─── SkillExecutor ────────────────────────────────────────────────────────────

const SkillExecutor = {

  // ── Public API ──────────────────────────────────────────────────────────────

  /**
   * Execute a skill in combat context.
   *
   * @param {object}        skillDef    — Skill definition from skill_trees.json
   * @param {object}        caster      — Combatant object (from CombatSystem._wrapCharacter/Enemy)
   * @param {Array<object>} targets     — Array of already-resolved target combatants (conscious)
   * @param {object}        combatState — Full combat state from CombatSystem.getState()
   * @param {object}        rng         — RNG instance (createRNG result)
   * @param {number}        [skillLevel=1] — Current level of the skill for the caster
   * @returns {Array<object>} events:
   *   - { type:'damage',  source, target, amount, damageType, isCrit }
   *   - { type:'heal',    source, target, amount }
   *   - { type:'shield',  source, target, amount }
   *   - { type:'status',  source, target, statusId }
   *   - { type:'summon',  source, companionType, skillLevel }
   *   - { type:'aura',    source, skillId }
   *   - { type:'resurrect', source, target }
   *   - { type:'dispel',  source, target, removedStatusId }
   *   - { type:'message', text }
   */
  execute(skillDef, caster, targets, combatState, rng, skillLevel = 1) {
    const events = [];

    // Guard: passive skills should never be executed
    if (skillDef.isPassive) {
      DebugLog.warn(`[skill] Attempted to execute passive skill: ${skillDef.id}`);
      return events;
    }

    // Aura activation — emit event, CombatSystem tracks active aura
    if (skillDef.isAura) {
      events.push({ type: 'aura', source: caster.id, skillId: skillDef.id, message: `${caster.name} activates ${skillDef.name}.` });
      // Auras may still apply statuses (to self by convention)
    }

    // Summon skills
    if (SUMMON_SKILL_IDS.has(skillDef.id)) {
      return this._handleSummon(skillDef, caster, skillLevel, events);
    }

    // Resurrection special case
    if (skillDef.id === 'holy_resurrection') {
      return this._handleResurrection(skillDef, caster, targets, events);
    }

    // Dispel/cleanse special case (nature_herbal_remedy cures a status)
    if (skillDef.id === 'nature_herbal_remedy') {
      return this._handleHerbalRemedy(skillDef, caster, targets, combatState, rng, skillLevel, events);
    }

    // Shout skills — apply buffs/statuses to all allies (targetingType may vary)
    // Shouting currently uses the same pipeline as buff; the flag is informational here.

    // Heal skills
    if (HEAL_SKILL_IDS.has(skillDef.id)) {
      return this._handleHeal(skillDef, caster, targets, combatState, rng, skillLevel, events);
    }

    // Shield skills
    if (SHIELD_SKILL_IDS.has(skillDef.id)) {
      return this._handleShield(skillDef, caster, targets, skillLevel, events);
    }

    // Damage skills (the majority)
    if (skillDef.damageMultiplier && skillDef.damageMultiplier.length > 0) {
      this._handleDamage(skillDef, caster, targets, rng, skillLevel, events);
    }

    // Status application (may accompany damage or stand alone)
    if (skillDef.applyStatus && skillDef.applyStatus.length > 0) {
      this._applyStatusesToTargets(skillDef, caster, targets, events);
    }

    // Pure utility / buff skills that only apply statuses (no damage, no heal)
    // are handled by applyStatus above; nothing more to do.

    return events;
  },

  // ── Private handlers ──────────────────────────────────────────────────────

  /**
   * Handle a damage skill against one or more targets.
   * Damage formula: baseDamage = mult × weaponOrSpellPower × (1 + statMod/10)
   *
   * @param {object}        skillDef
   * @param {object}        caster
   * @param {Array<object>} targets
   * @param {object}        rng
   * @param {number}        skillLevel
   * @param {Array<object>} events — mutated in place
   */
  _handleDamage(skillDef, caster, targets, rng, skillLevel, events) {
    const mult = this._getMultiplier(skillDef.damageMultiplier, skillLevel);
    const statMod = this._getStatMod(caster, skillDef.damageSource ?? 'weapon');
    const basePool = this._computeBasePool(caster, skillDef.damageSource ?? 'weapon', rng);
    const rawDamage = Math.round(basePool * mult * (1 + statMod / 10));
    const damageType = this._resolveDamageType(skillDef);

    for (const target of targets) {
      if (!target.isConscious) continue;

      // Check if target has Marked or CoupDeGrace — auto-crit consumed by CombatSystem
      const isCrit = this._hasConsumableCrit(target);
      const finalDamage = isCrit ? Math.round(rawDamage * 1.5) : rawDamage;

      events.push({
        type: 'damage',
        source: caster.id,
        target: target.id,
        amount: finalDamage,
        damageType,
        isCrit,
        message: isCrit
          ? `${caster.name} uses ${skillDef.name} — CRITICAL! ${finalDamage} ${damageType} damage to ${target.name}.`
          : `${caster.name} uses ${skillDef.name}: ${finalDamage} ${damageType} damage to ${target.name}.`,
      });

      if (isCrit) {
        // Signal CombatSystem to consume the trigger status
        events.push({ type: 'consume_crit_status', target: target.id });
      }

      DebugLog.event(
        `[skill] damage; caster=${caster.id} target=${target.id} skill=${skillDef.id} ` +
        `mult=${mult} statMod=${statMod} raw=${rawDamage} final=${finalDamage} type=${damageType} crit=${isCrit}`
      );
    }
  },

  /**
   * Handle a heal skill — targets are expected to be allies.
   * Heal formula: baseHeal = mult × spellPower × (1 + intellect_mod/10)
   *
   * Holy Nova (holy_holy_nova) is special: it heals allies and damages enemies
   * within the AoE. CombatSystem separates ally/enemy targets before calling;
   * we just heal everything in the targets array.
   *
   * @param {object}        skillDef
   * @param {object}        caster
   * @param {Array<object>} targets
   * @param {object}        combatState
   * @param {object}        rng
   * @param {number}        skillLevel
   * @param {Array<object>} events
   * @returns {Array<object>}
   */
  _handleHeal(skillDef, caster, targets, combatState, rng, skillLevel, events) {
    // Holy Nova also damages enemies — split handling
    if (skillDef.id === 'holy_holy_nova') {
      return this._handleHolyNova(skillDef, caster, targets, combatState, rng, skillLevel, events);
    }

    const mult = this._getMultiplier(skillDef.damageMultiplier, skillLevel) ?? 1.0;
    const intMod = this._getStatModByAttribute(caster, 'intellect');
    const spellPower = this._getSpellPower(caster);
    const healAmount = Math.round(spellPower * mult * (1 + intMod / 10));

    for (const target of targets) {
      if (!target.isConscious) continue;
      events.push({
        type: 'heal',
        source: caster.id,
        target: target.id,
        amount: healAmount,
        message: `${caster.name} heals ${target.name} for ${healAmount} HP.`,
      });
      DebugLog.event(`[skill] heal; caster=${caster.id} target=${target.id} skill=${skillDef.id} amount=${healAmount}`);
    }

    // Status application (e.g. nature_regrowth applies regenerating)
    if (skillDef.applyStatus && skillDef.applyStatus.length > 0) {
      this._applyStatusesToTargets(skillDef, caster, targets, events);
    }

    return events;
  },

  /**
   * Holy Nova — heals allies and damages enemies in the adjacent AoE.
   * CombatSystem passes all targets together; we sort them by allegiance.
   */
  _handleHolyNova(skillDef, caster, targets, combatState, rng, skillLevel, events) {
    const mult = this._getMultiplier(skillDef.damageMultiplier, skillLevel) ?? 1.0;
    const intMod = this._getStatModByAttribute(caster, 'intellect');
    const spellPower = this._getSpellPower(caster);
    const power = Math.round(spellPower * mult * (1 + intMod / 10));

    for (const target of targets) {
      if (!target.isConscious) continue;
      if (target.isPlayer === caster.isPlayer) {
        // Ally — heal
        events.push({
          type: 'heal',
          source: caster.id,
          target: target.id,
          amount: power,
          message: `Holy Nova heals ${target.name} for ${power} HP.`,
        });
      } else {
        // Enemy — damage (holy type)
        events.push({
          type: 'damage',
          source: caster.id,
          target: target.id,
          amount: power,
          damageType: 'holy',
          isCrit: false,
          message: `Holy Nova deals ${power} holy damage to ${target.name}.`,
        });
      }
    }

    return events;
  },

  /**
   * Handle Herbal Remedy — remove one debuff from target, minor heal.
   */
  _handleHerbalRemedy(skillDef, caster, targets, combatState, rng, skillLevel, events) {
    const intMod = this._getStatModByAttribute(caster, 'intellect');
    const spellPower = this._getSpellPower(caster);
    const minorHeal = Math.round(spellPower * 0.3 * (1 + intMod / 10));

    for (const target of targets) {
      if (!target.isConscious) continue;

      // Remove the first debuff found (if any)
      const debuff = target.statusEffects?.find(e => {
        // We don't have STATUS_EFFECTS imported here — use a simple heuristic:
        // remove anything that isn't a buff or neutral (id doesn't appear in known buffs set)
        return !KNOWN_BUFF_IDS.has(e.id);
      });
      if (debuff) {
        events.push({
          type: 'dispel',
          source: caster.id,
          target: target.id,
          removedStatusId: debuff.id,
          message: `${caster.name} cures ${debuff.id} from ${target.name}.`,
        });
      }

      // Minor heal
      if (minorHeal > 0) {
        events.push({
          type: 'heal',
          source: caster.id,
          target: target.id,
          amount: minorHeal,
          message: `${caster.name} restores ${minorHeal} HP to ${target.name}.`,
        });
      }
    }

    return events;
  },

  /**
   * Handle a shield skill — applies shielded status with an HP-absorb amount.
   */
  _handleShield(skillDef, caster, targets, skillLevel, events) {
    const mult = this._getMultiplier(skillDef.damageMultiplier, skillLevel) ?? 1.0;
    const intMod = this._getStatModByAttribute(caster, 'intellect');
    const spellPower = this._getSpellPower(caster);
    const shieldAmount = Math.round(spellPower * mult * (1 + intMod / 10));

    for (const target of targets) {
      if (!target.isConscious) continue;
      events.push({
        type: 'shield',
        source: caster.id,
        target: target.id,
        amount: shieldAmount,
        message: `${caster.name} shields ${target.name} for ${shieldAmount} HP.`,
      });
      // Also emit the status event so CombatSystem can apply the shielded status
      events.push({
        type: 'status',
        source: caster.id,
        target: target.id,
        statusId: 'shielded',
      });
      DebugLog.event(`[skill] shield; caster=${caster.id} target=${target.id} amount=${shieldAmount}`);
    }

    return events;
  },

  /**
   * Handle summon skills — emit a summon event for CombatSystem to resolve.
   * The actual companion creation (wrapping into a combatant) must happen in
   * CombatSystem because it owns the combatants map and grid.
   */
  _handleSummon(skillDef, caster, skillLevel, events) {
    const companionType = SUMMON_TYPE_MAP[skillDef.id] ?? 'unknown';
    events.push({
      type: 'summon',
      source: caster.id,
      companionType,
      skillLevel,
      message: `${caster.name} summons a ${companionType.replace(/_/g, ' ')}.`,
    });
    DebugLog.event(`[skill] summon; caster=${caster.id} type=${companionType} level=${skillLevel}`);
    return events;
  },

  /**
   * Handle Resurrection — revives an unconscious ally at 50% HP.
   */
  _handleResurrection(skillDef, caster, targets, events) {
    for (const target of targets) {
      // Resurrection targets unconscious allies — CombatSystem should pass them through
      if (target.isConscious) continue;
      events.push({
        type: 'resurrect',
        source: caster.id,
        target: target.id,
        hpFraction: 0.5,
        message: `${caster.name} resurrects ${target.name}!`,
      });
      DebugLog.event(`[skill] resurrect; caster=${caster.id} target=${target.id}`);
    }
    return events;
  },

  /**
   * Emit status events for all targets from skillDef.applyStatus.
   * @param {object}        skillDef
   * @param {object}        caster
   * @param {Array<object>} targets
   * @param {Array<object>} events — mutated
   */
  _applyStatusesToTargets(skillDef, caster, targets, events) {
    for (const target of targets) {
      if (!target.isConscious) continue;
      for (const statusId of skillDef.applyStatus) {
        events.push({
          type: 'status',
          source: caster.id,
          target: target.id,
          statusId,
          message: `${target.name} is afflicted by ${statusId}.`,
        });
      }
    }
  },

  // ── Math helpers ────────────────────────────────────────────────────────────

  /**
   * Get the damage/heal multiplier for the given skill level.
   * @param {number[]|null} multArray
   * @param {number}        skillLevel — 1-indexed
   * @returns {number}
   */
  _getMultiplier(multArray, skillLevel) {
    if (!multArray || multArray.length === 0) return 1.0;
    return multArray[Math.min(skillLevel - 1, multArray.length - 1)];
  },

  /**
   * Compute D&D-style attribute modifier: floor((val - 10) / 2).
   * @param {number} val
   * @returns {number}
   */
  _attributeMod(val) {
    return Math.floor(((val ?? 10) - 10) / 2);
  },

  /**
   * Get the stat modifier relevant to a damage source type.
   * @param {object} caster
   * @param {string} damageSource — "weapon"|"spell"|"both"
   * @returns {number}
   */
  _getStatMod(caster, damageSource) {
    const attrKey = DAMAGE_STAT[damageSource] ?? 'might';
    return this._attributeMod(caster.attributes?.[attrKey] ?? 10);
  },

  /**
   * Get the stat modifier for a specific attribute key.
   * @param {object} caster
   * @param {string} attrKey — e.g. 'intellect'
   * @returns {number}
   */
  _getStatModByAttribute(caster, attrKey) {
    return this._attributeMod(caster.attributes?.[attrKey] ?? 10);
  },

  /**
   * Compute the base damage pool for a combatant (weapon or spell).
   * For weapon: roll between weapon.damage.min and max (or unarmed default).
   * For spell: use a flat spell power value based on intellect.
   *
   * @param {object} caster
   * @param {string} damageSource
   * @param {object} rng
   * @returns {number}
   */
  _computeBasePool(caster, damageSource, rng) {
    if (damageSource === 'weapon' || damageSource === 'both') {
      // Mirror the logic from CombatSystem._getBaseDamage()
      if (caster.weaponDamage) {
        return rng.nextInt(caster.weaponDamage.min, caster.weaponDamage.max);
      }
      const weapon = caster.equipment?.weapon;
      if (weapon?.damage) {
        return rng.nextInt(weapon.damage.min ?? 5, weapon.damage.max ?? 10);
      }
      // Unarmed
      const mightMod = this._attributeMod(caster.attributes?.might ?? 10);
      return Math.max(1, 3 + mightMod);
    }
    // Spell
    return this._getSpellPower(caster);
  },

  /**
   * Compute spell power from intellect attribute.
   * Base: 8 + intellect_mod × 2 (scales smoothly, no weapon involved).
   *
   * @param {object} caster
   * @returns {number}
   */
  _getSpellPower(caster) {
    const intMod = this._attributeMod(caster.attributes?.intellect ?? 10);
    return Math.max(4, 8 + intMod * 2);
  },

  /**
   * Resolve the damage type string from a skill definition.
   * Uses the tree-level damageType if present on the skill, otherwise
   * falls back to the damageSource mapping.
   *
   * @param {object} skillDef
   * @returns {string}
   */
  _resolveDamageType(skillDef) {
    // Some skills in the data carry a damageType field; use it if present
    if (skillDef.damageType) return skillDef.damageType;
    // Infer from id prefix for known elemental trees
    const id = skillDef.id ?? '';
    if (id.startsWith('frost_'))   return 'frost';
    if (id.startsWith('fire_'))    return 'fire';
    if (id.startsWith('lightning_') || id.startsWith('storm_')) return 'lightning';
    if (id.startsWith('holy_'))    return 'holy';
    if (id.startsWith('nature_'))  return 'nature';
    if (id.startsWith('death_') || id.startsWith('death_knight_')) return 'death';
    if (id.startsWith('rune'))     return 'arcane';
    if (id.startsWith('spirit_'))  return 'spirit';
    // Fall back to damageSource
    return skillDef.damageSource === 'spell' ? 'magic' : 'physical';
  },

  /**
   * Check whether the target has a consumable auto-crit status (marked or coup_de_grace).
   * @param {object} target
   * @returns {boolean}
   */
  _hasConsumableCrit(target) {
    return (target.statusEffects ?? []).some(
      e => e.id === 'marked' || e.id === 'coup_de_grace'
    );
  },
};

// ─── Known buff IDs (used by herbal remedy dispel heuristic) ─────────────────

const KNOWN_BUFF_IDS = new Set([
  'hasted', 'shielded', 'regenerating', 'fortified', 'blessed',
  'enraged', 'inspired', 'invisible', 'defending',
  'aura_active', 'concentration',
]);

// ─── Debug exposure ───────────────────────────────────────────────────────────

if (typeof window !== 'undefined') {
  window.__skillExecutor = SkillExecutor;
}

export default SkillExecutor;
