// ─── Log entry category classifier ───────────────────────────────────────────

/**
 * Given a log entry message/category, return the CSS class for coloring.
 * @param {object} entry
 * @returns {string}
 */
function logCssClass(entry) {
  const cat = (entry.category ?? '').toLowerCase();
  const msg = (entry.message ?? '').toLowerCase();
  if (cat === 'crit' || msg.includes('critical')) return 'log-cat-crit';
  if (cat === 'miss' || msg.includes(' misses') || msg.includes('miss')) return 'log-cat-miss';
  if (cat === 'death' || msg.includes('defeated') || msg.includes('unconscious')) return 'log-cat-death';
  if (cat === 'status' || msg.includes('status') || msg.includes('poisoned') || msg.includes('stunned')) return 'log-cat-status';
  if (cat === 'combo' || msg.includes('combo')) return 'log-cat-combo';
  if (cat === 'skill' || msg.includes('casts') || msg.includes('uses')) return 'log-cat-skill';
  if (cat === 'heal' || msg.includes('heals') || msg.includes('restored')) return 'log-cat-heal';
  if (cat === 'system' || cat === 'round' || cat === 'start' || cat === 'end') return 'log-cat-system';
  if (cat === 'attack' || msg.includes('attack') || msg.includes('hits')) return 'log-cat-attack';
  return 'log-cat-default';
}

/**
 * Clamp an HP ratio to [0, 1], return CSS class for fill bar.
 * @param {number} hp
 * @param {number} maxHP
 * @returns {{ pct: number, cls: string }}
 */
function hpBarData(hp, maxHP) {
  const pct = maxHP > 0 ? Math.max(0, Math.min(1, hp / maxHP)) : 0;
  const cls = pct <= 0.25 ? 'critical' : pct <= 0.5 ? 'low' : '';
  return { pct, cls };
}

// ─── CombatScene ─────────────────────────────────────────────────────────────

export default class CombatScene {
  constructor() {
    /** @type {HTMLElement|null} Root container */
    this._el = null;
    /** @type {HTMLElement|null} */
    this._gridEl = null;
    /** @type {HTMLElement|null} */
    this._logEl = null;
    /** @type {HTMLElement|null} */
    this._actionEl = null;
    /** @type {HTMLElement|null} */
    this._turnBarEl = null;
    /** @type {HTMLElement|null} */
    this._skillsPopup = null;
    /** @type {HTMLElement|null} */
    this._endOverlay = null;

    /**
     * Interaction mode:
     *   'idle'                — waiting for player input choice
     *   'select_attack_target' — player clicked Attack, waiting to pick enemy tile
     *   'select_move'         — player clicked Move, waiting to pick empty tile
     */
    this._mode = 'idle';

    /** @type {Function|null} CombatSystem unsubscribe handle */
    this._unsubscribe = null;
    /** @type {number|null} setTimeout handle for enemy AI */
    this._enemyTurnTimer = null;
    /** @type {string} Scene to return to after combat ends */
    this._prevScene = 'worldMap';

    /** Cached turn order from last render pass (used by _getOccupant) */
    this._lastTurnOrder = [];
  }

  // ─── Lifecycle ──────────────────────────────────────────────────────────────

  /**
   * Initialize and mount the combat scene.
   *
   * @param {object} [opts]
   * @param {object} [opts.renderer]         PixiJS renderer (unused here, kept for signature)
   * @param {Array}  [opts.partyChars]       Party character instances
   * @param {Array}  [opts.enemies]          Enemy instances
   * @param {string} [opts.environment]      Biome string (e.g. 'forest')
   * @param {number} [opts.regionLevel]      Region difficulty level
   * @param {string} [opts.fromScene]        Scene name to return to after combat
   */
  async init({ renderer, partyChars, enemies, environment, regionLevel, fromScene } = {}) {
    DebugLog.info('[combat] CombatScene init');
    this._prevScene = fromScene ?? 'worldMap';

    injectStyles();

    // ── Resolve party ────────────────────────────────────────────
    if (!partyChars || !partyChars.length) {
      try {
        partyChars = CharacterSystem.getAll().filter(c => c.isHero).slice(0, 4);
      } catch (e) {
        DebugLog.warn('[combat] CharacterSystem.getAll failed, using empty party');
        partyChars = [];
      }
    }

    // ── Resolve enemies ──────────────────────────────────────────
    if (!enemies || !enemies.length) {
      try {
        enemies = EnemySystem.generateEncounter(regionLevel ?? 1, environment ?? 'forest');
      } catch (e) {
        DebugLog.warn(`[combat] EnemySystem.generateEncounter failed: ${e.message}`);
        try {
          const inst = EnemySystem.createInstance('orc_grunt', 1);
          enemies = inst ? [inst] : [];
        } catch (e2) {
          DebugLog.warn(`[combat] EnemySystem.createInstance also failed: ${e2.message}`);
          enemies = [];
        }
      }
    }

    // ── Build DOM ────────────────────────────────────────────────
    this._buildDOM();
    const overlay = document.getElementById('ui-overlay');
    if (overlay) {
      overlay.appendChild(this._el);
    } else {
      document.body.appendChild(this._el);
      DebugLog.warn('[combat] #ui-overlay not found, appended to body');
    }

    // ── Wire combat events ───────────────────────────────────────
    this._unsubscribe = CombatSystem.subscribe((type, data) => {
      this._onCombatEvent(type, data);
    });

    // ── M22: Initialise CombatLog (subscribes to CombatSystem internally) ──
    CombatLog.init();

    // Expose on window for debug console / Playwright
    window.__combatSystem = CombatSystem;
    window.__combatLog = CombatLog;

    // ── Start combat ─────────────────────────────────────────────
    CombatSystem.startCombat(partyChars, enemies, { environment, regionLevel });
    DebugLog.info(`[combat] startCombat: ${partyChars.length} heroes vs ${enemies.length} enemies`);

    // ── Initial render ───────────────────────────────────────────
    this._renderAll();

    // If the first combatant is an enemy, schedule their turn
    const cur = CombatSystem.getCurrentCombatant();
    if (cur && !cur.isPlayer) {
      this._scheduleEnemyTurn();
    }
  }

  update(_dt) {
    // No per-frame logic needed — combat is event-driven
  }

  async destroy() {
    clearTimeout(this._enemyTurnTimer);
    this._unsubscribe?.();
    CombatLog.destroy();
    this._el?.remove();
    this._el = null;
    window.__combatSystem = undefined;
    window.__combatLog = undefined;
    DebugLog.info('[combat] CombatScene destroyed');
  }

  // ─── DOM construction ───────────────────────────────────────────────────────

  _buildDOM() {
    const el = document.createElement('div');
    el.id = 'combat-scene';

    // Turn order bar
    const turnBar = document.createElement('div');
    turnBar.id = 'combat-turn-bar';
    this._turnBarEl = turnBar;

    // Main area
    const main = document.createElement('div');
    main.id = 'combat-main';

    // Grid wrapper + grid
    const gridWrap = document.createElement('div');
    gridWrap.id = 'combat-grid-wrap';
    const grid = document.createElement('div');
    grid.id = 'combat-grid';
    this._gridEl = grid;
    gridWrap.appendChild(grid);

    // Combat log
    const log = document.createElement('div');
    log.id = 'combat-log';
    log.innerHTML = `<div id="combat-log-title">Combat Log</div><div id="combat-log-entries"></div>`;
    this._logEl = log.querySelector('#combat-log-entries');

    main.appendChild(gridWrap);
    main.appendChild(log);

    // Action panel
    const actions = document.createElement('div');
    actions.id = 'combat-actions';
    this._actionEl = actions;

    // Skills popup (absolute within combat-scene)
    const skillsPopup = document.createElement('div');
    skillsPopup.id = 'combat-skills-popup';
    this._skillsPopup = skillsPopup;

    // End overlay (absolute within combat-scene)
    const endOverlay = document.createElement('div');
    endOverlay.id = 'combat-end-overlay';
    this._endOverlay = endOverlay;

    el.appendChild(turnBar);
    el.appendChild(main);
    el.appendChild(actions);
    el.appendChild(skillsPopup);
    el.appendChild(endOverlay);

    // Make el position:relative so absolute children are contained
    el.style.position = 'fixed';

    this._el = el;
  }

  // ─── Render methods ─────────────────────────────────────────────────────────

  _renderAll() {
    this._renderTurnBar();
    this._renderGrid();
    this._renderActions();
    this._renderLog();
  }

  // ── Co-op player lookup ─────────────────────────────────────────────────────

  /**
   * Return the 1-based player number (1–4) that controls this character,
   * or null if CoopSystem is unavailable or no assignment exists.
   *
   * @param {string} charId
   * @returns {number|null}
   */
  _getPlayerNumber(charId) {
    try {
      const cs = window.__coopSystem;
      if (!cs || typeof cs.getAssignments !== 'function') return null;
      const assignments = cs.getAssignments();
      if (!assignments) return null;

      const entries = assignments instanceof Map
        ? assignments.entries()
        : Object.entries(assignments);

      for (const [idx, assignedId] of entries) {
        if (assignedId === charId) {
          return parseInt(idx, 10) + 1; // convert 0-based index to 1-based label
        }
      }
    } catch (_) {
      // CoopSystem not loaded — silently skip
    }
    return null;
  }

  // ── Turn order bar ──────────────────────────────────────────────────────────

  _renderTurnBar() {
    if (!this._turnBarEl) return;
    const state = this._safeGetState();
    if (!state) return;

    const { turnOrder = [], combatants } = state;
    this._lastTurnOrder = turnOrder;

    const currentCombatant = CombatSystem.getCurrentCombatant?.() ?? null;
    const currentId = currentCombatant?.id ?? null;

    const chips = turnOrder.map(id => {
      const c = combatants?.get ? combatants.get(id) : (combatants?.[id]);
      if (!c) return '';

      const { pct, cls } = hpBarData(c.hp ?? 0, c.maxHP ?? 1);
      const pctPx = Math.round(pct * 100);
      const isCurrent = id === currentId;
      const isDead = !c.isConscious;
      const nameClass = c.isPlayer ? '' : 'enemy';
      const chipClass = [
        'turn-chip',
        isCurrent ? 'is-current' : '',
        isDead    ? 'is-dead'    : '',
      ].filter(Boolean).join(' ');
      const displayName = (c.name ?? 'Unknown').substring(0, 10);

      // Co-op player badge: only for party members, skip for enemies
      let playerBadgeHTML = '';
      if (c.isPlayer) {
        const playerNum = this._getPlayerNumber(c.id ?? id);
        if (playerNum != null) {
          const pClass = `p${playerNum}`;
          playerBadgeHTML = `<span class="chip-player-badge ${pClass}">P${playerNum}</span>`;
        }
      }

      return `
        <div class="${chipClass}" title="${c.name ?? ''}">
          <span class="chip-name ${nameClass}">${displayName}</span>
          ${playerBadgeHTML}
          <div class="chip-hp-bar">
            <div class="chip-hp-fill ${cls}" style="width:${pctPx}%"></div>
          </div>
        </div>
      `;
    });

    this._turnBarEl.innerHTML = chips.join('');

    // Scroll current chip into view
    const currentChip = this._turnBarEl.querySelector('.turn-chip.is-current');
    currentChip?.scrollIntoView?.({ behavior: 'smooth', inline: 'center', block: 'nearest' });
  }

  // ── Formation grid ──────────────────────────────────────────────────────────

  _renderGrid() {
    if (!this._gridEl) return;
    const state = this._safeGetState();
    const currentCombatant = CombatSystem.getCurrentCombatant?.() ?? null;

    // Build a position map: "col,row" => combatant
    const posMap = new Map();
    if (state?.combatants) {
      const entries = state.combatants instanceof Map
        ? state.combatants.entries()
        : Object.entries(state.combatants);
      for (const [, c] of entries) {
        if (c.col != null && c.row != null) {
          posMap.set(`${c.col},${c.row}`, c);
        }
      }
    }

    // Clear and rebuild grid (8 cols × 4 rows)
    this._gridEl.innerHTML = '';
    for (let row = 0; row < 4; row++) {
      for (let col = 0; col < 8; col++) {
        const tile = this._buildTile(col, row, posMap, currentCombatant);
        this._gridEl.appendChild(tile);
      }
    }
  }

  /**
   * Build a single tile element.
   * @param {number} col
   * @param {number} row
   * @param {Map<string,object>} posMap
   * @param {object|null} currentCombatant
   * @returns {HTMLElement}
   */
  _buildTile(col, row, posMap, currentCombatant) {
    const tile = document.createElement('div');
    const isPartySide = col < 4;
    const sideClass = isPartySide ? 'party-side' : 'enemy-side';
    tile.className = `combat-tile ${sideClass}`;
    tile.dataset.col = col;
    tile.dataset.row = row;

    // Mode-dependent interactive classes
    if (this._mode === 'select_move') {
      const occ = posMap.get(`${col},${row}`);
      if (!occ) tile.classList.add('move-target');
    } else if (this._mode === 'select_attack_target') {
      const occ = posMap.get(`${col},${row}`);
      if (occ && !occ.isPlayer && occ.isConscious !== false) {
        tile.classList.add('attack-target');
      }
    }

    // Combatant occupying this tile
    const occupant = posMap.get(`${col},${row}`);
    if (occupant) {
      tile.appendChild(this._buildAvatar(occupant, currentCombatant));

      // HP bar
      const { pct, cls } = hpBarData(occupant.hp ?? 0, occupant.maxHP ?? 1);
      const hpBar = document.createElement('div');
      hpBar.className = 'tile-hp-bar';
      hpBar.innerHTML = `<div class="tile-hp-fill ${cls}" style="width:${Math.round(pct * 100)}%"></div>`;
      tile.appendChild(hpBar);

      // Status pips
      const effects = occupant.statusEffects ?? [];
      if (effects.length > 0) {
        const statusWrap = document.createElement('div');
        statusWrap.className = 'tile-status';
        effects.slice(0, 4).forEach(fx => {
          const pip = document.createElement('span');
          pip.className = 'status-pip';
          pip.title = fx.name ?? fx.id ?? fx;
          pip.style.background = this._statusColor(fx);
          statusWrap.appendChild(pip);
        });
        tile.appendChild(statusWrap);
      }
    }

    // Click handler
    tile.addEventListener('click', () => this._onTileClick(col, row));

    return tile;
  }

  /**
   * Build the combatant avatar circle.
   * @param {object} c
   * @param {object|null} cur
   * @returns {HTMLElement}
   */
  _buildAvatar(c, cur) {
    const avatar = document.createElement('div');
    const isCurrent = cur && c.id === cur.id;
    const isUnconscious = c.isConscious === false;
    const isDefending = (c.statusEffects ?? []).some(
      fx => (fx.id ?? fx) === 'defending' || (fx.name ?? '') === 'Defending'
    );

    const classes = [
      'combatant-avatar',
      c.isPlayer ? '' : 'enemy',
      isCurrent  ? 'current-turn' : '',
      isDefending ? 'defending' : '',
      isUnconscious ? 'unconscious' : '',
    ].filter(Boolean).join(' ');

    avatar.className = classes;
    const letter = (c.name ?? '?').charAt(0).toUpperCase();
    avatar.textContent = letter;
    avatar.title = `${c.name} — HP: ${c.hp ?? '?'}/${c.maxHP ?? '?'}`;

    return avatar;
  }

  /**
   * Return a CSS color for a status effect pip.
   * @param {string|object} fx
   * @returns {string}
   */
  _statusColor(fx) {
    const id = (fx.id ?? fx).toString().toLowerCase();
    if (id.includes('poison')) return '#40d040';
    if (id.includes('burn') || id.includes('fire')) return '#e06020';
    if (id.includes('stun') || id.includes('daze')) return '#e0e020';
    if (id.includes('freeze') || id.includes('cold')) return '#60c0e8';
    if (id.includes('defend')) return '#4080c0';
    if (id.includes('bleed')) return '#c02020';
    if (id.includes('regen') || id.includes('heal')) return '#40c060';
    return '#a09070';
  }

  // ── Combat log ──────────────────────────────────────────────────────────────

  _renderLog() {
    if (!this._logEl) return;
    let entries = [];
    try {
      entries = CombatSystem.getLog(20) ?? [];
    } catch (e) {
      // getLog may not be available yet
    }

    const last10 = entries.slice(-10);
    let lastRound = null;

    const html = last10.map(entry => {
      let sep = '';
      if (entry.round != null && entry.round !== lastRound) {
        lastRound = entry.round;
        sep = `<div class="log-round-sep">— Round ${entry.round} —</div>`;
      }
      const cls = logCssClass(entry);
      const msg = this._escapeHtml(entry.message ?? '');
      return `${sep}<div class="log-entry ${cls}">${msg}</div>`;
    }).join('');

    this._logEl.innerHTML = html;
    // Auto-scroll to bottom
    this._logEl.scrollTop = this._logEl.scrollHeight;
  }

  // ── Action panel ────────────────────────────────────────────────────────────

  _renderActions() {
    if (!this._actionEl) return;
    const state = this._safeGetState();
    this._actionEl.innerHTML = '';

    if (!state?.active) {
      this._actionEl.innerHTML = '<span class="action-label">Combat ended</span>';
      return;
    }

    const cur = CombatSystem.getCurrentCombatant?.() ?? null;
    if (!cur) return;

    // Enemy turn
    if (!cur.isPlayer) {
      this._actionEl.innerHTML = `
        <div class="combat-enemy-thinking">
          <span>${cur.name ?? 'Enemy'} is acting</span>
          <span class="thinking-dots">
            <span>.</span><span>.</span><span>.</span>
          </span>
        </div>
      `;
      return;
    }

    // Player turn
    const { actionTaken = false, moveTaken = false } = state;
    const label = document.createElement('span');
    label.className = 'action-label';
    label.textContent = `${cur.name}'s turn:`;
    this._actionEl.appendChild(label);

    if (actionTaken) {
      // Only End Turn remains
      const btn = this._makeBtn('End Turn', 'end-turn', () => {
        this._mode = 'idle';
        this._closeSkillsPopup();
        this._scheduleNextTurn();
      });
      this._actionEl.appendChild(btn);
      return;
    }

    // Move button (only if not yet moved)
    if (!moveTaken) {
      const moveBtn = this._makeBtn('Move', '', () => {
        this._mode = this._mode === 'select_move' ? 'idle' : 'select_move';
        this._closeSkillsPopup();
        this._renderGrid();
      });
      if (this._mode === 'select_move') moveBtn.style.borderColor = '#40a060';
      this._actionEl.appendChild(moveBtn);
    }

    // Attack
    const attackBtn = this._makeBtn('Attack', '', () => {
      this._mode = this._mode === 'select_attack_target' ? 'idle' : 'select_attack_target';
      this._closeSkillsPopup();
      this._renderGrid();
    });
    if (this._mode === 'select_attack_target') attackBtn.style.borderColor = '#c83020';
    this._actionEl.appendChild(attackBtn);

    // Skills
    const skillBtn = this._makeBtn('Skills', '', () => {
      this._toggleSkillsPopup(cur);
    });
    this._actionEl.appendChild(skillBtn);

    // Defend
    const defendBtn = this._makeBtn('Defend', '', () => {
      this._closeSkillsPopup();
      this._mode = 'idle';
      try { CombatSystem.executeDefend(); } catch (e) { DebugLog.warn(`[combat] executeDefend: ${e.message}`); }
      this._renderAll();
      this._scheduleNextTurn();
    });
    this._actionEl.appendChild(defendBtn);

    // Pass
    const passBtn = this._makeBtn('Pass', '', () => {
      this._closeSkillsPopup();
      this._mode = 'idle';
      try { CombatSystem.executePass(); } catch (e) { DebugLog.warn(`[combat] executePass: ${e.message}`); }
      this._renderAll();
      this._scheduleNextTurn();
    });
    this._actionEl.appendChild(passBtn);
  }

  /**
   * Create a styled combat button.
   * @param {string} label
   * @param {string} extraClass
   * @param {Function} onClick
   * @returns {HTMLButtonElement}
   */
  _makeBtn(label, extraClass, onClick) {
    const btn = document.createElement('button');
    btn.className = ['combat-btn', extraClass].filter(Boolean).join(' ');
    btn.textContent = label;
    btn.addEventListener('click', onClick);
    return btn;
  }

  // ─── Skills popup ────────────────────────────────────────────────────────────

  _toggleSkillsPopup(combatant) {
    if (!this._skillsPopup) return;
    const isVisible = this._skillsPopup.classList.contains('visible');
    if (isVisible) {
      this._closeSkillsPopup();
      return;
    }
    this._buildSkillsPopup(combatant);
    this._skillsPopup.classList.add('visible');
  }

  _closeSkillsPopup() {
    this._skillsPopup?.classList.remove('visible');
  }

  _buildSkillsPopup(combatant) {
    if (!this._skillsPopup) return;

    const skills = combatant?.skills ?? combatant?.knownSkills ?? [];
    let html = `<div class="skills-popup-title">Skills — ${combatant?.name ?? ''}</div>`;

    if (!skills.length) {
      html += `<div class="skill-empty">No skills known</div>`;
    } else {
      html += skills.slice(0, 8).map(sk => {
        const name = sk.name ?? sk.skillId ?? sk.id ?? 'Unknown';
        const cost = sk.manaCost ? `${sk.manaCost} MP` : '';
        return `
          <div class="skill-entry" data-tree="${sk.treeId ?? ''}" data-skill="${sk.skillId ?? sk.id ?? ''}">
            <span class="skill-name">${this._escapeHtml(name)}</span>
            ${cost ? `<span class="skill-cost">${cost}</span>` : ''}
          </div>
        `;
      }).join('');
    }

    this._skillsPopup.innerHTML = html;

    // Bind click handlers on each skill entry
    this._skillsPopup.querySelectorAll('.skill-entry').forEach(entry => {
      entry.addEventListener('click', () => {
        const treeId = entry.dataset.tree;
        const skillId = entry.dataset.skill;
        this._closeSkillsPopup();
        this._mode = 'idle';
        // Skills targeting: for now use first eligible target
        const state = this._safeGetState();
        let targetId = null;
        if (state?.combatants) {
          const entries = state.combatants instanceof Map
            ? [...state.combatants.values()]
            : Object.values(state.combatants);
          const enemy = entries.find(c => !c.isPlayer && c.isConscious !== false);
          targetId = enemy?.id ?? null;
        }
        try {
          const result = CombatSystem.executeSkill(treeId, skillId, targetId);
          DebugLog.event(`[combat] Skill used; tree=${treeId} skill=${skillId} success=${result?.success}`);
        } catch (e) {
          DebugLog.warn(`[combat] executeSkill error: ${e.message}`);
        }
        this._renderAll();
        this._scheduleNextTurn();
      });
    });
  }

  // ─── Tile click handler ──────────────────────────────────────────────────────

  _onTileClick(col, row) {
    if (this._mode === 'select_attack_target') {
      const occ = this._getOccupant(col, row);
      if (!occ || occ.isPlayer) return;
      if (occ.isConscious === false) return;

      let result;
      try {
        result = CombatSystem.executeAttack(occ.id);
      } catch (e) {
        DebugLog.warn(`[combat] executeAttack error: ${e.message}`);
        return;
      }

      if (result?.success) {
        // Show floating damage
        this._showDamageFloat(col, row, result.outcome, result.damage);
        DebugLog.event(`[combat] attack; target=${occ.id} damage=${result.damage} outcome=${result.outcome}`);
      }
      this._mode = 'idle';
      this._renderAll();
      this._scheduleNextTurn();

    } else if (this._mode === 'select_move') {
      const occ = this._getOccupant(col, row);
      if (occ) return; // tile occupied

      let result;
      try {
        result = CombatSystem.executeMove(col, row);
      } catch (e) {
        DebugLog.warn(`[combat] executeMove error: ${e.message}`);
        return;
      }

      if (result?.success) {
        DebugLog.event(`[combat] move; col=${col} row=${row}`);
      }
      this._mode = 'idle';
      this._renderAll();
    }
  }

  // ─── Turn flow ───────────────────────────────────────────────────────────────

  /**
   * Check for combat end, then advance to the next combatant after a brief delay.
   */
  _scheduleNextTurn() {
    try {
      const { over, winner } = CombatSystem.checkCombatEnd();
      if (over) {
        setTimeout(() => this._showEndScreen({ winner }), 800);
        return;
      }
    } catch (e) {
      // checkCombatEnd not yet available
    }

    setTimeout(() => {
      let next = null;
      try { next = CombatSystem.nextTurn(); } catch (e) { /* */ }
      this._renderAll();
      if (next && !next.isPlayer) {
        this._scheduleEnemyTurn();
      }
    }, 300);
  }

  /**
   * Schedule the enemy AI turn with a short randomised delay for feel.
   */
  _scheduleEnemyTurn() {
    const delay = 420 + Math.random() * 380;
    this._enemyTurnTimer = setTimeout(() => {
      const cur = CombatSystem.getCurrentCombatant?.() ?? null;
      if (!cur || cur.isPlayer) return;

      DebugLog.event(`[combat] enemy turn; id=${cur.id} name=${cur.name}`);

      try {
        // CombatSystem.executeEnemyTurn is the AI dispatch method
        CombatSystem.executeEnemyTurn(cur);
      } catch (e) {
        // Fallback: try a basic attack on a random party member
        DebugLog.warn(`[combat] executeEnemyTurn failed, falling back: ${e.message}`);
        this._fallbackEnemyAction(cur);
      }

      this._renderAll();

      try {
        const { over, winner } = CombatSystem.checkCombatEnd();
        if (over) {
          setTimeout(() => this._showEndScreen({ winner }), 500);
          return;
        }
      } catch (e) { /* */ }

      this._scheduleNextTurn();
    }, delay);
  }

  /**
   * Minimal fallback if executeEnemyTurn is unavailable.
   * Attacks a random conscious party member.
   * @param {object} cur
   */
  _fallbackEnemyAction(cur) {
    const state = this._safeGetState();
    if (!state?.combatants) return;
    const entries = state.combatants instanceof Map
      ? [...state.combatants.values()]
      : Object.values(state.combatants);
    const target = entries.find(c => c.isPlayer && c.isConscious !== false);
    if (!target) return;
    try {
      CombatSystem.executeAttack(target.id);
    } catch (e) { /* */ }
  }

  // ─── Combat event handler ────────────────────────────────────────────────────

  _onCombatEvent(type, data) {
    DebugLog.event(`[combat] event; type=${type}`);

    switch (type) {
      case 'combat:over':
        // Allow the final render to happen first
        this._renderAll();
        setTimeout(() => this._showEndScreen(data ?? {}), 800);
        break;

      case 'combat:hit': {
        // Floating damage number at the target's tile
        const pos = data.position;
        if (pos != null) {
          const text = data.isCrit ? `CRIT ${data.damage}!` : String(data.damage);
          this._spawnFloatingTextAtTile(pos.col, pos.row, text, data.isCrit ? 'crit' : 'damage');
          this._pulseHpBar(pos.col, pos.row);
        }
        this._renderAll();
        break;
      }

      case 'combat:miss': {
        const pos = data.position;
        if (pos != null) {
          this._spawnFloatingTextAtTile(pos.col, pos.row, 'MISS', 'miss');
        }
        this._renderAll();
        break;
      }

      case 'combat:heal': {
        const pos = data.position;
        if (pos != null) {
          this._spawnFloatingTextAtTile(pos.col, pos.row, `+${data.amount}`, 'heal');
        }
        this._renderAll();
        break;
      }

      case 'combat:status': {
        const pos = data.position;
        if (pos != null) {
          this._spawnFloatingTextAtTile(pos.col, pos.row, data.statusName ?? data.statusId ?? 'status', 'status');
        }
        this._renderAll();
        break;
      }

      case 'combat:xp': {
        // Show XP float near the first survivor's position
        const first = (data.survivors ?? [])[0];
        if (first) {
          this._spawnFloatingTextAtTile(first.col, first.row, `+${data.amount} XP`, 'xp');
        }
        break;
      }

      case 'character:levelup': {
        // Large level-up toast + floating text
        const pos = data.position;
        if (pos != null) {
          this._spawnFloatingTextAtTile(pos.col, pos.row, 'Level Up!', 'xp');
        }
        this._showLevelUpToast(data.name ?? data.charId ?? 'Hero', data.newLevel ?? '?');
        break;
      }

      case 'combat:attack':
      case 'combat:skill':
        // Hit/miss/heal/status visual feedback handled by the granular events above.
        // Still re-render the combat state.
        this._renderAll();
        break;

      default:
        this._renderAll();
        break;
    }
  }

  // ─── Victory / Defeat overlay ────────────────────────────────────────────────

  _showEndScreen(data) {
    let result = data;
    // Finalize combat if not already done
    try {
      result = CombatSystem.endCombat() ?? data;
    } catch (e) {
      // endCombat may already have been called
    }

    const winner  = result?.winner ?? data?.winner;
    const xp      = result?.xp ?? {};
    const loot    = result?.loot ?? [];
    const levelUps = result?.levelUps ?? [];

    DebugLog.info(`[combat] combat over; winner=${winner}`);

    if (!this._endOverlay) return;

    const isVictory = winner === 'party';
    const headlineText = isVictory ? 'VICTORY' : 'DEFEAT';
    const headlineCls  = isVictory ? 'victory' : 'defeat';

    // Build XP rows
    const xpRows = Object.entries(xp).map(([charId, amount]) => `
      <div class="end-xp-row">
        <span>${this._escapeHtml(charId)}</span>
        <span class="end-xp-value">+${amount} XP</span>
      </div>
    `).join('');

    // Build level-up notices
    const levelUpHtml = levelUps.map(lu => `
      <div class="end-levelup">${this._escapeHtml(lu.name ?? lu.charId ?? '')} leveled up to ${lu.newLevel ?? '?'}!</div>
    `).join('');

    // Build loot list
    const lootHtml = loot.length
      ? loot.map(item => `<div class="end-loot-item">${this._escapeHtml(item.name ?? item.itemId ?? item)}</div>`).join('')
      : '<div class="end-loot-item" style="color:#706050;font-style:italic;">No loot</div>';

    this._endOverlay.innerHTML = `
      <div class="end-headline ${headlineCls}">${headlineText}</div>
      ${isVictory ? `
        <div class="end-rewards">
          ${xpRows ? `<div class="end-rewards-title">Experience Gained</div>${xpRows}` : ''}
          ${levelUpHtml}
          <div class="end-rewards-title" style="margin-top:10px;">Loot</div>
          <div class="end-loot-list">${lootHtml}</div>
        </div>
      ` : `
        <div style="font-size:clamp(13px,1.5vw,16px); color:#a09070; text-align:center; max-width:360px;">
          Your party has fallen.<br>The saga continues...
        </div>
      `}
      <button class="end-continue-btn" id="combat-continue-btn">
        ${isVictory ? 'Continue' : 'Return'}
      </button>
    `;

    this._endOverlay.classList.add('visible');

    document.getElementById('combat-continue-btn')?.addEventListener('click', () => {
      DebugLog.info(`[combat] continue; returning to ${this._prevScene}`);
      SceneManager.transition(this._prevScene);
    });
  }

  // ─── M22: FloatingText helpers ───────────────────────────────────────────────

  /**
   * Convert a grid tile position to screen (page) coordinates and spawn a
   * FloatingText label there.
   *
   * @param {number} col
   * @param {number} row
   * @param {string} text
   * @param {'damage'|'heal'|'miss'|'crit'|'status'|'xp'} type
   */
  _spawnFloatingTextAtTile(col, row, text, type) {
    if (!this._gridEl) return;
    const tile = this._gridEl.querySelector(`[data-col="${col}"][data-row="${row}"]`);
    if (!tile) return;

    const rect = tile.getBoundingClientRect();
    const screenX = rect.left + rect.width  / 2;
    const screenY = rect.top  + rect.height / 3; // spawn in upper third of tile

    FloatingText.spawn(screenX, screenY, text, type);
  }

  /**
   * Briefly flash the HP bar on the tile at (col, row) to signal damage taken.
   * @param {number} col
   * @param {number} row
   */
  _pulseHpBar(col, row) {
    if (!this._gridEl) return;
    const tile = this._gridEl.querySelector(`[data-col="${col}"][data-row="${row}"]`);
    if (!tile) return;

    tile.classList.add('hp-bar-hit');
    // Remove the class after the animation duration (0.3s) so it can re-trigger
    setTimeout(() => tile.classList.remove('hp-bar-hit'), 350);
  }

  /**
   * Show a large centered level-up toast for the named character.
   * @param {string} name
   * @param {number|string} newLevel
   */
  _showLevelUpToast(name, newLevel) {
    const existing = document.querySelector('.levelup-toast');
    if (existing) existing.remove();

    const toast = document.createElement('div');
    toast.className = 'levelup-toast';
    toast.textContent = `${name} reached Level ${newLevel}!`;

    const container = this._el ?? document.body;
    container.appendChild(toast);

    // After 2.2s begin fade-out, then remove
    setTimeout(() => {
      toast.classList.add('hiding');
      setTimeout(() => toast.remove(), 550);
    }, 2200);
  }

  // ─── Floating damage numbers ─────────────────────────────────────────────────

  /**
   * Spawn a floating damage/miss number over a grid tile.
   * This legacy method is retained for backwards compatibility with tile-click
   * handler paths. M22 events now use _spawnFloatingTextAtTile() instead.
   * @param {number} col
   * @param {number} row
   * @param {string} outcome   — 'hit'|'miss'|'crit'|'dodge'
   * @param {number} [damage]
   */
  _showDamageFloat(col, row, outcome, damage) {
    if (!this._gridEl) return;
    // Find the tile element by data attributes
    const tile = this._gridEl.querySelector(`[data-col="${col}"][data-row="${row}"]`);
    if (!tile) return;

    const float = document.createElement('div');
    let text = '';
    let cls = 'dmg';

    if (outcome === 'miss' || outcome === 'dodge') {
      text = 'MISS';
      cls = 'miss';
    } else if (outcome === 'crit') {
      text = damage != null ? `CRIT ${damage}!` : 'CRIT!';
      cls = 'crit';
    } else {
      text = damage != null ? String(damage) : 'HIT';
      cls = 'dmg';
    }

    float.className = `dmg-float ${cls}`;
    float.textContent = text;
    float.style.pointerEvents = 'none';

    // Tile needs position:relative (already set in CSS)
    tile.appendChild(float);
    float.addEventListener('animationend', () => float.remove(), { once: true });
  }

  // ─── Helpers ─────────────────────────────────────────────────────────────────

  /**
   * Get CombatSystem state safely (returns null on error).
   * @returns {object|null}
   */
  _safeGetState() {
    try {
      return CombatSystem.getState();
    } catch (e) {
      return null;
    }
  }

  /**
   * Find the combatant occupying the given tile position.
   * @param {number} col
   * @param {number} row
   * @returns {object|null}
   */
  _getOccupant(col, row) {
    const state = this._safeGetState();
    if (!state?.combatants) return null;
    const entries = state.combatants instanceof Map
      ? [...state.combatants.values()]
      : Object.values(state.combatants);
    return entries.find(c => c.col === col && c.row === row) ?? null;
  }

  /**
   * Escape HTML special characters.
   * @param {string} str
   * @returns {string}
   */
  _escapeHtml(str) {
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }
}
